		v1.y * v2.z - v1.z * v2.y,
		v1.z * v2.x - v1.x * v2.z,
		v1.x * v2.y - v1.y * v2.x
	});
}

static char		*norme2(char **str, int i, int k, char *buf)
{
	char	*buf2;

	while ((*str)[i] == '0')
		i++;
	if ((*str)[i] == '.')
	{
		if ((*str)[i + 1] && (*str)[i + 1] >= '5' && (*str)[i + 1] <= '9')
			buf = ft_strdup("1");
		else
			buf = ft_strdup("0");
	}
	else
	{
		while ((*str)[i + k] != '.')
			k++;
		buf = ft_chmalloc_zend(k);
		if ((*str)[i + k + 1] && (*str)[i + k + 1] >= '5' &&
		(*str)[i + k + 1] <= '9')
			buf2 = ft_chsum(*str, "1.0");
		else
			buf2 = ft_strdup(*str);
		ft_strncpy(buf, buf2, k);
		free(buf2);
	}
	return (buf);
}

