int				ft_special_secure_atoi(const char *nptr, int *error)
{
	int result;
	int sign;

	*error = FALSE;
	result = 0;
	sign = FALSE;
	if (*nptr == '-')
	{
		sign = TRUE;
		nptr++;
	}
	if (!(*nptr >= '0' && *nptr <= '9'))
		*error = TRUE;
	else
		while (*nptr >= '0' && *nptr <= '9')
		{
			result = secure_mul(result, 10, error);
			result = secure_add(result, ((sign) ?
						-1 * (*nptr - '0') : (*nptr - '0')), error);
			nptr++;
		}
	if (*nptr != ' ' && *nptr != '\0')
		*error = TRUE;
	return (result);
}

bool StringIsInteger(const char* string) {
  if (!string) {
    return false;
  }

  // check that the first digit isn't led with a 0
  if (*string < '1' || *string > '9') {
    return false;
  }

  // check the rest
  for (const char* c = string+1; *c != '\0'; ++c) {
    if (!isdigit((unsigned int) *c)) {
      return false;
    }
  }
  return true;
}

