            if(UtopiaIoctl(pu32VDEC_EX_Inst,(MS_U32)E_VDEC_EX_V2_CMD_GET_CONTROL, (void*)(&IO_arg)) != UTOPIA_STATUS_SUCCESS)
            {
                VPRINTF("[Fail][%s,%d]\n",__FUNCTION__,__LINE__);
