                }
            }
        }
        #if EVENT_PATCH
        if(bBlockFail)
        {
            MsOS_DelayTask(100);
        }
        #endif
    }
}

static void mkshop(void) {
    struct mkroom *sroom;
    int i = -1;
    char *ep = (char *)0; /* (init == lint suppression) */

    gottype: for (sroom = &rooms[0];; sroom++) {
        if (sroom->hx < 0)
            return;
        if (sroom - rooms >= nroom) {
            pline("rooms not closed by -1?");
            return;
        }
        if (sroom->rtype != OROOM)
            continue;
        if (has_dnstairs(sroom) || has_upstairs(sroom))
            continue;
        if ((flags.debug && ep && sroom->doorct != 0) || sroom->doorct == 1)
            break;
    }
    if (!sroom->rlit) {
        int x, y;

        for (x = sroom->lx - 1; x <= sroom->hx + 1; x++)
            for (y = sroom->ly - 1; y <= sroom->hy + 1; y++)
                levl[x][y].lit = 1;
        sroom->rlit = 1;
    }

    if (i < 0) { /* shoptype not yet determined */
        int j;

        /* pick a shop type at random */
        for (j = rnd(100), i = 0; (j -= shtypes[i].prob) > 0; i++)
            continue;

        /* big rooms cannot be wand or book shops,
         * - so make them general stores
         */
        if (isbig(sroom) && (shtypes[i].symb == WAND_CLASS || shtypes[i].symb == SPBOOK_CLASS))
            i = 0;
    }
    sroom->rtype = SHOPBASE + i;

    /* set room bits before stocking the shop */
    topologize(sroom);

    /* stock the room with a shopkeeper and artifacts */
    stock_room(i, sroom);
}

static float ran1(long *idum)
{
   int j;
   long k;
   static long iy = 0;
   static long iv[NTAB];
   float temp;

   if (*idum <= 0  ||  !iy) {
      if (-(*idum) < 1) *idum = 1;
      else *idum = -(*idum);
      for (j=NTAB+7; j>=0; j--) {
	 k     = (*idum) / IQ;
	 *idum = IA * (*idum - k * IQ) - IR * k;
	 if (*idum < 0) *idum += IM;
	 if (j < NTAB)  iv[j]  = *idum;
      }
      iy = iv[0];
   }
   k = (*idum) / IQ;
   *idum = IA * (*idum - k * IQ) - IR * k;
   if (*idum < 0) *idum += IM;
   j = iy / NDIV;
   iy = iv[j];
   iv[j] = *idum;
   if ((temp = AM * iy) > RNMX) return RNMX;
   else return temp;

}

