void				*ft_memccpy(void *dst, const void *src, int c, int n)
{
	unsigned char	*udst;
	unsigned char	*usrc;
	int				idx;

	idx = 0;
	udst = (unsigned char *)dst;
	usrc = (unsigned char *)src;
	while (idx < n)
	{
		*udst = *usrc;
		if (*usrc == (unsigned char)c)
			return (++udst);
		idx++;
		udst++;
