bool downlink_process_pkg (uint8_t * data)
{
    bool return_package;
    downlink_package *p;

    p = (downlink_package *) (data);

    sleep = 0;

    switch (p->opcode & 0xF0)
    {

        case GET:
            return_package = downlink_handle_get_package (p);
            break;

        case SET:
            return_package = downlink_handle_set_package (p);
            break;

        case BYE:
            sleep = p->value;
            p->id = 0;
            p->value = 0;
            return_package = true;
            break;

        case ECHO:
            return_package = true;
            break;

        default:
            return_package = false;
            break;
    }

    p->opcode |= return_package ? RET : ERROR;

    return bt_send ( (void *) p, DOWNLINK_PACKAGE_LENGTH);
}

int point_pop(space *e, char x[10])
{
    point_pointer before = (point_pointer)malloc(sizeof(point_node));
    point_pointer copy = (point_pointer)malloc(sizeof(point_node));

    before = NULL;
    copy = e->point_first;

    if (e->point_amount == 0)
        return 0;

    if (e->point_amount == 1 && strcmp(e->point_first->info.name, x) == 0)
    {
        copy = e->point_first;
        e->point_first = copy->next;
        free(copy);
        e->point_amount--;
        return 1;
    }

    if (strcmp(copy->info.name, x) == 0)
    {
        e->point_first = copy->next;
        free(copy);
        e->point_amount--;
        return 1;
    }

    while (copy->next != NULL && copy->info.name != x)
    {
        before = copy;
        copy = copy->next;
    }

    if (copy->next == NULL && copy->info.name != x)
        return 0;

    before->next = copy->next;
    free(copy);
    e->point_amount--;
    return 1;
}

