static void
NB_ScheduleTrafficNotify(NB_Navigation* navigation, uint32 millisecs, nb_boolean initial)
{
    PAL_Instance* pal = NULL;
    NB_TrafficType trafficFlags = NB_TrafficType_None;
    NB_Error err = NE_OK;

    if (!navigation)
    {
        return;
    }

    err = NB_RouteInformationGetTrafficFlags(navigation->navState->navRoute, &trafficFlags);
    if (err || (trafficFlags & NB_TrafficType_Notification) == 0)
    {
        return;
    }

    pal = NB_ContextGetPal(navigation->context);

    if (navigation->navState->trafficNotifyRetries < navigation->configuration.trafficNotifyMaximumRetries)
    {
        navigation->navState->trafficNotifyRetries++;
    }
    else
    {
        NB_NavigationCancelTrafficNotify(navigation);
        return;
    }

    navigation->startNotification = initial;

    PAL_TimerSet(pal, millisecs, NB_TrafficNotifyTimerCallback, navigation);

}

int line_Count(char* input){
	FILE *in_file;
	int lineCount=1;
	in_file = fopen(input, "r");
	if(in_file == NULL){
		printf("Failure to open file for reading.\n");
	}
	else{	
		int c=0;
		while(!feof(in_file)){
			c = fgetc(in_file);
    		if(c == '\n'){
      			lineCount++;
    		}	
		}
	}	
	fclose(in_file);
	return lineCount;
}

static int try_rfn_cut(char *fname)
{
	FILE *tmp;
	char *p;

	p = fname + strlen(fname) - 1;
	for (; p > fname; p--)
		if (*p == '.') break;
	*p = 0;

	if((tmp = fopen(fname, "rb"))) {
		fclose(tmp);
		return 1;
	}
	return 0;
}

enum halmac_ret_status
reg_w32_sdio_8822b(struct halmac_adapter *adapter, u32 offset, u32 value)
{
	enum halmac_ret_status status = HALMAC_RET_SUCCESS;

	if (adapter->halmac_state.mac_pwr == HALMAC_MAC_POWER_OFF ||
	    (offset & (4 - 1)) !=  0) {
		if ((offset & 0xFFFF0000) == 0 && ((offset & (4 - 1)) == 0)) {
			status = w_indir_sdio_88xx(adapter, offset, value,
						   HALMAC_IO_DWORD);
		} else {
			if ((offset & 0xFFFF0000) == 0)
				offset |= WLAN_IOREG_OFFSET;

			status = cnv_to_sdio_bus_offset_88xx(adapter, &offset);
			if (status != HALMAC_RET_SUCCESS) {
				PLTFM_MSG_ERR("[ERR]convert offset\n");
				return status;
			}
			PLTFM_SDIO_CMD52_W(offset, (u8)(value & 0xFF));
			PLTFM_SDIO_CMD52_W(offset + 1,
					   (u8)((value >> 8) & 0xFF));
			PLTFM_SDIO_CMD52_W(offset + 2,
					   (u8)((value >> 16) & 0xFF));
			PLTFM_SDIO_CMD52_W(offset + 3,
					   (u8)((value >> 24) & 0xFF));
		}
	} else {
		if ((offset & 0xFFFF0000) == 0)
			offset |= WLAN_IOREG_OFFSET;

		status = cnv_to_sdio_bus_offset_88xx(adapter, &offset);
		if (status != HALMAC_RET_SUCCESS) {
			PLTFM_MSG_ERR("[ERR]convert offset\n");
			return status;
		}
		PLTFM_SDIO_CMD53_W32(offset, value);
	}

	return status;
}

extFloat80_t extF80_rem( extFloat80_t a, extFloat80_t b )
{
    union { struct extFloat80M s; extFloat80_t f; } uA;
    uint_fast16_t uiA64;
    uint_fast64_t uiA0;
    bool signA;
    int_fast32_t expA;
    uint_fast64_t sigA;
    union { struct extFloat80M s; extFloat80_t f; } uB;
    uint_fast16_t uiB64;
    uint_fast64_t uiB0;
    int_fast32_t expB;
    uint_fast64_t sigB;
    struct exp32_sig64 normExpSig;
    int_fast32_t expDiff;
    struct uint128 rem, shiftedSigB;
    uint_fast32_t q, recip32;
    uint_fast64_t q64;
    struct uint128 term, altRem, meanRem;
    bool signRem;
    struct uint128 uiZ;
    uint_fast16_t uiZ64;
    uint_fast64_t uiZ0;
    union { struct extFloat80M s; extFloat80_t f; } uZ;

    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
    uA.f = a;
    uiA64 = uA.s.signExp;
    uiA0  = uA.s.signif;
    signA = signExtF80UI64( uiA64 );
    expA  = expExtF80UI64( uiA64 );
    sigA  = uiA0;
    uB.f = b;
    uiB64 = uB.s.signExp;
    uiB0  = uB.s.signif;
    expB  = expExtF80UI64( uiB64 );
    sigB  = uiB0;
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
    if ( expA == 0x7FFF ) {
        if (
               (sigA & UINT64_C( 0x7FFFFFFFFFFFFFFF ))
            || ((expB == 0x7FFF) && (sigB & UINT64_C( 0x7FFFFFFFFFFFFFFF )))
        ) {
            goto propagateNaN;
        }
        goto invalid;
    }
    if ( expB == 0x7FFF ) {
        if ( sigB & UINT64_C( 0x7FFFFFFFFFFFFFFF ) ) goto propagateNaN;
        /*--------------------------------------------------------------------
        | Argument b is an infinity.  Doubling `expB' is an easy way to ensure
        | that `expDiff' later is less than -1, which will result in returning
        | a canonicalized version of argument a.
        *--------------------------------------------------------------------*/
        expB += expB;
    }
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
    if ( ! expB ) expB = 1;
    if ( ! (sigB & UINT64_C( 0x8000000000000000 )) ) {
        if ( ! sigB ) goto invalid;
        normExpSig = softfloat_normSubnormalExtF80Sig( sigB );
        expB += normExpSig.exp;
        sigB = normExpSig.sig;
    }
    if ( ! expA ) expA = 1;
    if ( ! (sigA & UINT64_C( 0x8000000000000000 )) ) {
        if ( ! sigA ) {
            expA = 0;
            goto copyA;
        }
        normExpSig = softfloat_normSubnormalExtF80Sig( sigA );
        expA += normExpSig.exp;
        sigA = normExpSig.sig;
    }
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
    expDiff = expA - expB;
    if ( expDiff < -1 ) goto copyA;
    rem = softfloat_shortShiftLeft128( 0, sigA, 32 );
    shiftedSigB = softfloat_shortShiftLeft128( 0, sigB, 32 );
    if ( expDiff < 1 ) {
        if ( expDiff ) {
            --expB;
            shiftedSigB = softfloat_shortShiftLeft128( 0, sigB, 33 );
            q = 0;
        } else {
            q = (sigB <= sigA);
            if ( q ) {
                rem =
                    softfloat_sub128(
                        rem.v64, rem.v0, shiftedSigB.v64, shiftedSigB.v0 );
            }
        }
    } else {
        recip32 = softfloat_approxRecip32_1( sigB>>32 );
        expDiff -= 30;
        for (;;) {
            q64 = (uint_fast64_t) (uint32_t) (rem.v64>>2) * recip32;
            if ( expDiff < 0 ) break;
            q = (q64 + 0x80000000)>>32;
            rem = softfloat_shortShiftLeft128( rem.v64, rem.v0, 29 );
            term = softfloat_mul64ByShifted32To128( sigB, q );
            rem = softfloat_sub128( rem.v64, rem.v0, term.v64, term.v0 );
            if ( rem.v64 & UINT64_C( 0x8000000000000000 ) ) {
                rem =
                    softfloat_add128(
                        rem.v64, rem.v0, shiftedSigB.v64, shiftedSigB.v0 );
            }
            expDiff -= 29;
        }
        /*--------------------------------------------------------------------
        | (`expDiff' cannot be less than -29 here.)
        *--------------------------------------------------------------------*/
        q = (uint32_t) (q64>>32)>>(~expDiff & 31);
        rem = softfloat_shortShiftLeft128( rem.v64, rem.v0, expDiff + 30 );
        term = softfloat_mul64ByShifted32To128( sigB, q );
        rem = softfloat_sub128( rem.v64, rem.v0, term.v64, term.v0 );
        if ( rem.v64 & UINT64_C( 0x8000000000000000 ) ) {
            altRem =
                softfloat_add128(
                    rem.v64, rem.v0, shiftedSigB.v64, shiftedSigB.v0 );
            goto selectRem;
        }
    }
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
    do {
        altRem = rem;
        ++q;
        rem =
            softfloat_sub128(
                rem.v64, rem.v0, shiftedSigB.v64, shiftedSigB.v0 );
    } while ( ! (rem.v64 & UINT64_C( 0x8000000000000000 )) );
 selectRem:
    meanRem = softfloat_add128( rem.v64, rem.v0, altRem.v64, altRem.v0 );
    if (
        (meanRem.v64 & UINT64_C( 0x8000000000000000 ))
            || (! (meanRem.v64 | meanRem.v0) && (q & 1))
    ) {
        rem = altRem;
    }
    signRem = signA;
    if ( rem.v64 & UINT64_C( 0x8000000000000000 ) ) {
        signRem = ! signRem;
        rem = softfloat_sub128( 0, 0, rem.v64, rem.v0 );
    }
    return
        softfloat_normRoundPackToExtF80(
            signRem, rem.v64 | rem.v0 ? expB + 32 : 0, rem.v64, rem.v0, 80 );
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
 propagateNaN:
    uiZ = softfloat_propagateNaNExtF80UI( uiA64, uiA0, uiB64, uiB0 );
    uiZ64 = uiZ.v64;
    uiZ0  = uiZ.v0;
    goto uiZ;
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
 invalid:
    softfloat_raiseFlags( softfloat_flag_invalid );
    uiZ64 = defaultNaNExtF80UI64;
    uiZ0  = defaultNaNExtF80UI0;
    goto uiZ;
    /*------------------------------------------------------------------------
    *------------------------------------------------------------------------*/
 copyA:
    if ( expA < 1 ) {
        sigA >>= 1 - expA;
        expA = 0;
    }
    uiZ64 = packToExtF80UI64( signA, expA );
    uiZ0  = sigA;
 uiZ:
    uZ.s.signExp = uiZ64;
    uZ.s.signif  = uiZ0;
    return uZ.f;

}

void reapZombies(void)
{
	int pid;
	int status = 0;

	signal(SIGINT, SIG_IGN);
	for(int i = 0; i < numPids; i++)
	{
		if((pid=waitpid(pids[i], &status, WNOHANG))>0)
		{
			fprintf(stderr, "Completed: %d (%d)\n", pid, STATUS(status));
		}
	}
	signal(SIGINT, SIG_DFL);
	return;
}

__attribute__((used)) static int tda9874a_initialize(struct CHIPSTATE *chip)
{
	if (tda9874a_SIF > 2)
		tda9874a_SIF = 1;
	if (tda9874a_STD >= ARRAY_SIZE(tda9874a_modelist))
		tda9874a_STD = 0;
	if(tda9874a_AMSEL > 1)
		tda9874a_AMSEL = 0;

	if(tda9874a_SIF == 1)
		tda9874a_GCONR = 0xc0;	/* sound IF input 1 */
	else
		tda9874a_GCONR = 0xc1;	/* sound IF input 2 */

	tda9874a_ESP = tda9874a_STD;
	tda9874a_mode = (tda9874a_STD < 5) ? 0 : 1;

	if(tda9874a_AMSEL == 0)
		tda9874a_NCONR = 0x01; /* auto-mute: analog mono input */
	else
		tda9874a_NCONR = 0x05; /* auto-mute: 1st carrier FM or AM */

	tda9874a_setup(chip);
	return 0;
}

static int
vnc_client_key(ggi_vnc_client *client)
{
	struct ggi_visual *vis = client->owner;
	ggi_vnc_priv *priv = VNC_PRIV(vis);
	uint32_t key;

	if (client->buf_size < 8) {
		/* wait for more data */
		client->action = vnc_client_key;
		return 0;
	}

	if (client->input) {
		DPRINT("client_key\n");

		memcpy(&key, &client->buf[4], sizeof(key));
		priv->key(priv->gii_ctx, client->buf[1], ntohl(key));
	}

	return vnc_remove(client, 8);
}

int main(int argc, char* argv[])
{
  struct DataStruct data;
  int parse = 1;
  int publish = 1;

  fprintf(stderr, "Starting %s\n", argv[0]);

  // Set defaults

  data.mqtt_port = DEFAULT_MQTT_PORT;
  strncpy(data.mqtt_host, DEFAULT_MQTT_HOST, STR_MAX);
  strncpy(data.neurio_host, DEFAULT_NEURIO_HOST, STR_MAX);
  strncpy(data.mqtt_username, DEFAULT_MQTT_USERNAME, STR_MAX);
  strncpy(data.mqtt_password, DEFAULT_MQTT_PASSWORD, STR_MAX);
  strncpy(data.mqtt_topic, DEFAULT_MQTT_TOPIC, STR_MAX);
  strncpy(data.config_file, DEFAULT_CONFIG_FILE, STR_MAX);
  strncpy(data.neurio_username, DEFAULT_NEURIO_USERNAME, STR_MAX);
  strncpy(data.neurio_password, DEFAULT_NEURIO_PASSWORD, STR_MAX);
  data.sleep.tv_sec = DEFAULT_SLEEP;
  data.sleep.tv_nsec = 0;
  data.buffer_size = 2048 * 1024;
  data.use_timestamp = false;

  // Parse the command line

  while(1)
  {
		static struct option long_options[] =
		{
			{"no-parse",     no_argument,       0, 'x'},
			{"no-publish",   no_argument,       0, 'y'},
			{"verbose",      no_argument,       0, 'v'},
			{"quiet",        no_argument,       0, 'q'},
			{"config-file",  required_argument, 0, 'c'},
			{0, 0, 0, 0}
		};

		int option_index = 0;
    int c = getopt_long(argc, argv, "c:xyqv", long_options, &option_index);

    if(c == -1)
    {
      break;
    }

    switch(c)
    {
      case 0:
        if(long_options[option_index].flag != 0)
        {
          break;
        }
        debug_print("option %s", long_options[option_index].name);
        break;
      case 'x':
        parse = false;
        break;
      case 'y':
        publish = false;
        break;
      case 'v':
        verbose_flag = true;
        break;
      case 'q':
        verbose_flag = false;
        break;
      case 'c':
        strncpy(data.config_file, optarg, STR_MAX);
        break;
      case '?':
        break;
      default:
        debug_print("Exiting due to getopt ... (%c)\n", c);
        return EXIT_FAILURE;
    }
  }

  fprintf(stderr, "Reading config from %s\n", data.config_file);
  read_config(&data, data.config_file);

  // Dump config 

  debug_print("mqtt_username = %s\n", data.mqtt_username);
  debug_print("mqtt_password = %s\n", data.mqtt_password);
  debug_print("mqtt_topic = %s\n", data.mqtt_topic);
  debug_print("mqtt_host = %s\n", data.mqtt_host);
  debug_print("mqtt_port = %d\n", data.mqtt_port);
  debug_print("neurio_host = %s\n", data.neurio_host);
  debug_print("sleep = %ld, %ld\n", data.sleep.tv_sec, 
      data.sleep.tv_nsec);
  debug_print("buffer_size = %d\n", (int)data.buffer_size);

  // Allocate CURL buffer.

  if(!(data.buffer = malloc(data.buffer_size)))
  {
    fprintf(stderr, "Unable to allocate memory for buffer.\n\n");
    return EXIT_FAILURE;
  }
  data.buffer_counter = 0;
  debug_print("Allocated buffer at %p of size %d\n", data.buffer, 
      (int)data.buffer_size);

  // Setup cURL lib
  curl_global_init(CURL_GLOBAL_NOTHING);
  data.curl_handle = curl_easy_init();
  if(!data.curl_handle)
  {
    fprintf(stderr, "Unable to setup cURL library.\n\n");
    return EXIT_FAILURE;
  }

  char _host[STR_MAX];
  snprintf(_host, STR_MAX, "http://%s/current-sample", data.neurio_host);
  debug_print("cURL host = %s\n", _host);

  curl_easy_setopt(data.curl_handle, CURLOPT_URL, _host);
  curl_easy_setopt(data.curl_handle, CURLOPT_WRITEFUNCTION, WriteMemoryCallback);
  curl_easy_setopt(data.curl_handle, CURLOPT_WRITEDATA, (void *)&data);
  curl_easy_setopt(data.curl_handle, CURLOPT_USERAGENT, "libcurl-agent/1.0");
  curl_easy_setopt(data.curl_handle, CURLOPT_HTTPAUTH, CURLAUTH_BASIC);
  curl_easy_setopt(data.curl_handle, CURLOPT_USERNAME, data.neurio_username);
  curl_easy_setopt(data.curl_handle, CURLOPT_PASSWORD, data.neurio_password);

  // Setup MQTT
  snprintf(data.mqtt_client_id, STR_MAX, "%s_%ld", 
      MQTT_CLIENT_ID, (long int)getpid());
  debug_print("mqtt_client_id = %s\n", data.mqtt_client_id);

  char _address[STR_MAX];
  snprintf(_address, STR_MAX, "tcp://%s:%d", data.mqtt_host, data.mqtt_port);

  MQTTAsync_create(&data.mqtt_client, _address, data.mqtt_client_id,
      MQTTCLIENT_PERSISTENCE_NONE, NULL);

  MQTTAsync_setCallbacks(data.mqtt_client, (void *)&data, 
      mqtt_on_connection_lost, NULL, mqtt_delivery_complete);

  MQTTAsync_connectOptions conn_opts = MQTTAsync_connectOptions_initializer;
  data.mqtt_conn_opts = conn_opts;
  data.mqtt_conn_opts.keepAliveInterval = 5;
  data.mqtt_conn_opts.cleansession = 1;
  data.mqtt_conn_opts.username = data.mqtt_username;
  data.mqtt_conn_opts.password = data.mqtt_password;
  data.mqtt_conn_opts.onSuccess = mqtt_on_connection;
  data.mqtt_conn_opts.automaticReconnect = 1;

  int rc;
  if ((rc = MQTTAsync_connect(data.mqtt_client, &data.mqtt_conn_opts)) != MQTTCLIENT_SUCCESS)
  {
    fprintf(stderr, "MQTT Failed to start connect, return code %d\n", rc);
    return EXIT_FAILURE;
  }

  // Now setup sigterm handler
  struct sigaction action;
  memset(&action, 0, sizeof(action));
  action.sa_handler = term;
  sigaction(SIGTERM, &action, NULL);
  sigaction(SIGINT,  &action, NULL);

  for(;;)
  {
    if(sigterm)
    {
      fprintf(stderr, "Exiting loop due to signal.\n");
      break;
    }

    if(!get_neurio_data(&data))
    {
      fprintf(stderr, "Unable to get neurio data\n");
      continue;
    }
    if(parse)
    {
      if(!parse_neurio_data(&data))
      {
        fprintf(stderr, "Unable to parse neurio data\n");
        continue;
      }

      if(publish)
      {
        if(!publish_to_thingsboard(&data))
        {
          fprintf(stderr, "Unable to publish to thingsboard\n");
        }
      }
    }

    if(!sigterm)
    {
      nanosleep(&data.sleep, NULL); 
    }
  }

  free(data.buffer);

  curl_easy_cleanup(data.curl_handle);
  curl_global_cleanup();

  MQTTAsync_destroy(&data.mqtt_client);

  fprintf(stderr, "Bye!\n");

  return 0;
}

