        // for Nss Dimension to be 2
        if (pSib->tripleStream) { 
            if (flag & TRUE_TS_N2) {
                // for triple stream
                return true;
            }
        } else  if (pSib->dualStream) {
            if (flag & TRUE_DS_N2) {
                // for dual stream
                return true;
            }
        }
    } else if (pSib->usedNss == NSS_DIM_1) {
        // for Nss Dimension to be 1
        if (pSib->tripleStream) {
            if (flag & TRUE_TS_N1) {
                // for triple stream
                return true;
