void	*ft_memmove(void *dst, const void *src, size_t n)
{
	void *ret;

	ret = dst;
	if (dst == src)
	{
		return (dst);
	}
	else if (src < dst && dst < src + n)
	{
		dst += n;
		src += n;
		while (n--)
			*(unsigned char *)(--dst) = *(unsigned char *)(--src);
		return (ret);
	}
	else
	{
		while (n--)
			*(unsigned char *)(dst++) = *(unsigned char *)(src++);
		return (ret);
	}
}

