char	**ft_split(char const *s, char c)
{
	char	**str;
	int		element;
	int		index;

	str = NULL;
	if (!s)
		return (NULL);
	element = (count((char *)s, c));
	str = ft_calloc(element + 1, sizeof(char *));
	if (!str)
		return (NULL);
	index = 0;
	while ((*s != '\0' && index < element))
	{
		while (*s == c && *s != '\0')
			s++;
		str[index] = stradd((char *)s, c);
		if (!(str[index]))
			return (strfree(str, index));
		while (*s != c && *s != '\0')
			s++;
		index++;
	}
	str[index] = (NULL);
	return (str);
}

