int kdtree_nns(int row, int col, Kdtree *tree, Point *v)
{
    /* Nearest neighbor search as seen in class
     * Step 1: we find the smallest box containing the pixel
     * Step 2: we find the nearest neighbor inside that box and calculate its distance
     * Step 3: we do a recursive search over the tree, checking box colisions and looking for a closer nuclei
     * https://courses.cs.washington.edu/courses/cse373/02au/lectures/lecture22l.pdf
     * https://yal.cc/rectangle-circle-intersection-test/
     * 
    */

    /* Step 1 */
    Kdnode *current = kdnode_search(tree, col, row);

    /* Step 2 */
    double closest_distance = INT32_MAX;
    int closest_point;
    kdnode_nns_box(current, v, row, col, &closest_distance, &closest_point);
    // printf("(%f, %f)\n", v[closest_point].X, v[closest_point].Y);

    /* Step 3 */
    current = tree->head;
    kdnode_nns(current, v, row, col, &closest_distance, &closest_point);
    // printf("(%f, %f)\n", v[closest_point].X, v[closest_point].Y);
    return closest_point;
}

static int wormhole_age(struct attrib *a, void *owner)
{
    building *entry = (building *)owner;
    region *exit = (region *)a->data.v;
    int maxtransport = entry->size;
    region *r = entry->region;
    unit *u = r->units;

    UNUSED_ARG(owner);
    for (; u != NULL && maxtransport != 0; u = u->next) {
        if (u->building == entry) {
            message *m = NULL;
            if (u->number > maxtransport || has_limited_skills(u)) {
                m = msg_message("wormhole_requirements", "unit region", u, u->region);
            }
            else if (exit != NULL) {
                move_unit(u, exit, NULL);
                maxtransport -= u->number;
                m = msg_message("wormhole_exit", "unit region", u, exit);
                add_message(&exit->msgs, m);
            }
            if (m != NULL) {
                add_message(&u->faction->msgs, m);
                msg_release(m);
            }
        }
    }

    remove_building(&r->buildings, entry);
    ADDMSG(&r->msgs, msg_message("wormhole_dissolve", "region", r));

    /* age returns 0 if the attribute needs to be removed, !=0 otherwise */
    return AT_AGE_KEEP;
}

