int
tapdisk_image_check_td_request(td_image_t *image, td_request_t treq)
{
	int rdonly;
	td_driver_t *driver;
	td_disk_info_t *info;

	driver = image->driver;
	if (!driver)
		return -ENODEV;

	info   = &driver->info;
	rdonly = td_flag_test(image->flags, TD_OPEN_RDONLY);

	if (treq.op != TD_OP_READ && treq.op != TD_OP_WRITE)
		goto fail;

	if (treq.op == TD_OP_WRITE && rdonly)
		goto fail;

	if (treq.secs <= 0 || treq.sec + treq.secs > info->size)
		goto fail;

	return 0;

fail:
	ERR(-EINVAL, "bad td request on %s (%s, %"PRIu64"): %d at %"PRIu64,
	    image->name, (rdonly ? "ro" : "rw"), info->size, treq.op,
	    treq.sec + treq.secs);
	return -EINVAL;

}

int Thread_init(int preempt, ...) {
	// interface_addresses();
	assert(preempt == 0 || preempt == 1);
	assert(current == NULL);
	root.handle = &root;
	current = &root;
	nthreads = 1;
	if (preempt) {
		// initialize preemptive scheduling
		{
			struct sigaction sa;
			memset(&sa, '\0', sizeof sa);
			sa.sa_handler = (void (*)())interrupt;
			if (sigaction(SIGVTALRM, &sa, NULL) < 0)
				return 0;
		}
		{
			struct itimerval it;
			it.it_value.tv_sec     =  0;
			it.it_value.tv_usec    = 50;
			it.it_interval.tv_sec  =  0;
			it.it_interval.tv_usec = 50;
			if (setitimer(ITIMER_VIRTUAL, &it, NULL) < 0)
				return 0;
		}
	}
	return 1;
}

static int
archive_write_mtree_finish_entry(struct archive_write *a)
{
	struct mtree_writer *mtree = a->format_data;
	struct archive_entry *entry;
	const char *name;
	int ret;

	entry = mtree->entry;
	if (entry == NULL) {
		archive_set_error(&a->archive, ARCHIVE_ERRNO_PROGRAMMER,
		    "Finished entry without being open first.");
		return (ARCHIVE_FATAL);
	}
	mtree->entry = NULL;

	if (archive_entry_nlink(entry) != 1 && 
	    archive_entry_filetype(entry) != AE_IFDIR)
		archive_string_sprintf(&mtree->buf,
		    " nlink=%u", archive_entry_nlink(entry));

	if ((name = archive_entry_gname(entry)) != NULL) {
		archive_strcat(&mtree->buf, " gname=");
		mtree_quote(mtree, name);
	}
	if ((name = archive_entry_uname(entry)) != NULL) {
		archive_strcat(&mtree->buf, " uname=");
		mtree_quote(mtree, name);
	}
	if ((name = archive_entry_fflags_text(entry)) != NULL) {
		archive_strcat(&mtree->buf, " flags=");
		mtree_quote(mtree, name);
	}

	archive_string_sprintf(&mtree->buf,
	    " time=%jd mode=%o gid=%jd uid=%jd",
	    (intmax_t)archive_entry_mtime(entry),
	    archive_entry_mode(entry) & 07777,
	    (intmax_t)archive_entry_gid(entry),
	    (intmax_t)archive_entry_uid(entry));

	switch (archive_entry_filetype(entry)) {
	case AE_IFLNK:
		archive_strcat(&mtree->buf, " type=link link=");
		mtree_quote(mtree, archive_entry_symlink(entry));
		archive_strcat(&mtree->buf, "\n");
		break;
	case AE_IFSOCK:
		archive_strcat(&mtree->buf, " type=socket\n");
		break;
	case AE_IFCHR:
		archive_string_sprintf(&mtree->buf,
		    " type=char device=native,%d,%d\n",
		    archive_entry_rdevmajor(entry),
		    archive_entry_rdevminor(entry));
		break;
	case AE_IFBLK:
		archive_string_sprintf(&mtree->buf,
		    " type=block device=native,%d,%d\n",
		    archive_entry_rdevmajor(entry),
		    archive_entry_rdevminor(entry));
		break;
	case AE_IFDIR:
		archive_strcat(&mtree->buf, " type=dir\n");
		break;
	case AE_IFIFO:
		archive_strcat(&mtree->buf, " type=fifo\n");
		break;
	case AE_IFREG:
	default:	/* Handle unknown file types as regular files. */
		archive_string_sprintf(&mtree->buf, " type=file size=%jd\n",
		    (intmax_t)archive_entry_size(entry));
		break;
	}

	archive_entry_free(entry);

	if (mtree->buf.length > 32768) {
		ret = (a->compressor.write)(a, mtree->buf.s, mtree->buf.length);
		archive_string_empty(&mtree->buf);
	} else
		ret = ARCHIVE_OK;

	return (ret == ARCHIVE_OK ? ret : ARCHIVE_FATAL);
}

static tls_err_t tls_config(struct tls_ctx *ctx, int endpoint_type)
{
	LOG(LOG_DEBUG, "Configuring TLS");
	int ret = mbedtls_ssl_config_defaults(&ctx->conf,
		endpoint_type,
		MBEDTLS_SSL_TRANSPORT_STREAM,
		MBEDTLS_SSL_PRESET_DEFAULT);
	if (ret != 0) {
		LOG(LOG_ERR, "Unable to configure TLS defaults");
		LOGF(LOG_DEBUG, "mbedtls_ssl_config_defaults returned %d (0x%04X)", ret, ret);
		return -1;
	}
	mbedtls_ssl_conf_rng(&ctx->conf, mbedtls_ctr_drbg_random, &ctx->ctr_drbg);
	mbedtls_ssl_conf_dbg(&ctx->conf, tls_log, NULL);
	mbedtls_debug_set_threshold(MBEDTLS_DBG_TARGET_LEVEL);
	return 0;
}

