			else
			{
				l.x1 = x;
				l.y1 = b.y1;
				//printf("Test4\n");
			}
		}
	}

	x = ((b.y2 - l.y1)/(l.y2 - l.y1))*(l.x2 - l.x1) + l.x1;
	if(l.x1 <= x && l.x2 >= x)
	{
		if((b.y2<=l.y1 && b.y2>=l.y2) || (b.y2>=l.y1 && b.y2<=l.y2))
