int connect_to_ext(char* pIpAddress, u32 port, u32 timeout_ms) {

    struct sockaddr_in servaddr;
    int res = 0;


    sockfd = socket(AF_INET, SOCK_STREAM, 0);
    if (sockfd == -1) {
            fprintf(logfd, "socket creation failed...\n");
            fflush(logfd);
            return(res);
        }

    // set timeout
    struct timeval tv;
    tv.tv_sec = timeout_ms/1000;
    tv.tv_usec = (timeout_ms % 1000) * 1000;
    if (setsockopt(sockfd, SOL_SOCKET, SO_RCVTIMEO, (const char*)&tv, sizeof tv) != 0) {
        fprintf(logfd, "setsockopt creation failed...\n");
        fflush(logfd);
        return(res);
    }

    bzero(&servaddr, sizeof(servaddr));
    // assign IP, PORT
    servaddr.sin_family = AF_INET;
    servaddr.sin_addr.s_addr = inet_addr(pIpAddress);
    servaddr.sin_port = htons(port);

    if (connect(sockfd, (SA*)&servaddr, sizeof(servaddr)) != 0) {
            fprintf(logfd, "connection with the server failed...\n");
            fflush(logfd);
            CLOSE_SOCKET(sockfd);
            return(res);
    }

    res = 1;

    return res;

}

bool splitLineToFields(int num_of_fields, int prefix_length, char
buf[MAX_NMEA_LEN], char**
tokens_array){

    char* p = &buf[prefix_length]; // start line after prefix
    int i=0;
    char* last_token = NULL;

    while (i < num_of_fields) {
        if (*p == DELIMITER)
        {
            *p = END_OF_TOKEN;
            if (last_token != NULL){
                tokens_array[i++] = last_token;
            }
            // new field
            p++;
            if (*p == DELIMITER)
            {
                // empty field
                tokens_array[i++] = NULL;
                last_token = NULL;
            } else {
                // non-empty field
                last_token = p;
            }
        } else {
            // same field
            if (i == num_of_fields-1) // last field
            {
                tokens_array[i++] = last_token;
            }
            p++;
        }
    }
    return true;
}

