			obj->draw_data.cur_objs.cur_mat.power);
		rtn = col_mul_coef(&obj->draw_data.cur_objs.cur_mat.specular, blinn);
		rtn = col_mul(&rtn, &obj->draw_data.cur_objs.cur_light.intensity);
	}
	return (rtn);
}

