static enum edit_key_code esc_seq_to_key(char *seq)
{
	char last, *pos;
	int param1 = -1, param2 = -1;
	enum edit_key_code ret = EDIT_KEY_NONE;

	last = '\0';
	for (pos = seq; *pos; pos++) {
		last = *pos;
	}

	if (seq[1] >= '0' && seq[1] <= '9') {
		param1 = atoi(&seq[1]);
		pos = os_strchr(seq, ';');
		if (pos) {
			param2 = atoi(pos + 1);
		}
	}

	if (seq[0] == '[') {
		ret = esc_seq_to_key1(param1, param2, last);
	} else if (seq[0] == 'O') {
		ret = esc_seq_to_key2(param1, param2, last);
	}

	if (ret != EDIT_KEY_NONE) {
		return ret;
	}

	edit_clear_line();
	printf("\rUnknown escape sequence '%s'\n", seq);
	edit_redraw();
	return EDIT_KEY_NONE;
}

int		get_word_len(char *s, int c, int index)
{
	int	end;
	int	start;
	int	word_len;

	end = 0;
	word_len = 0;
	start = index;
	while (s[index] != c && s[index])
	{
		index++;
		end = index;
	}
	word_len = end - start;
	return (word_len);
}

