int
i2c_write(i2c_bus_t* dev, const void* vdata, int len){
    const char* data = (const char*)vdata;
    int count = 0;

    dprintf("Writing %d bytes as slave 0x%x\n", len, dev->regs->address);
    /** Configure Master Rx mode **/
    clear_pending(dev);
    dev->regs->control |= I2CCON_ACK_EN;
    dev->regs->status = I2CSTAT_ENABLE | I2CSTAT_MODE_STX;
    /* Wait for addressed as slave */
    dprintf("TX waiting for master\n");
    while(!irq_pending(dev));

    if(addressed_as_slave(dev)){
        while(count < len && busy(dev)){
            /* After ACK period, IRQ is pending */
            dev->regs->data = *data++;
            clear_pending(dev);
            while(!irq_pending(dev) && busy(dev));
            count++;
        }
        dprintf("wrote %d bytes\n", count);
        dev->regs->status = ~(I2CSTAT_ENABLE | I2CSTAT_MODE_SRX);
        clear_pending(dev);
        return count;
    }else{
        dprintf("Not addressed as slave\n");
        return -1;
    }
}

static void settings_write_reply_callback(u16 sender_id, u8 len, u8 msg_[], void *context)
{
  (void)sender_id;
  (void)context;
  msg_settings_write_resp_t *msg = (void *)msg_;

  static struct setting *s = NULL;
  const char *section = NULL, *setting = NULL, *value = NULL;

  if (msg->status != 0) {
    return;
  }

  if (!settings_parse_setting(len - 1, msg->setting, &section, &setting, &value, NULL)) {
    piksi_log(LOG_WARNING, "Error in write reply message");
    return;
  }

  s = settings_lookup(section, setting);
  if (s == NULL) {
    piksi_log(LOG_WARNING, "Write reply for non-existent setting");
    return;
  }

  if (strcmp(s->value, value) == 0) {
    /* Setting unchanged */
    return;
  }

  /* This is an assignment, call notify function */
  strncpy(s->value, value, BUFSIZE);
  s->dirty = true;

  return;
}

int cloudfs_copy_object(const char* src, const char* dst)
{
  debugf(DBG_LEVEL_EXT, "cloudfs_copy_object(%s, %s) lensrc=%d, lendst=%d", src,
         dst, strlen(src), strlen(dst));

  char* dst_encoded = curl_escape(dst, 0);
  char* src_encoded = curl_escape(src, 0);

  //convert encoded string (slashes are encoded as well) to encoded string with slashes
  char* slash;
  while ((slash = strstr(src_encoded, "%2F"))
         || (slash = strstr(src_encoded, "%2f")))
  {
    *slash = '/';
    memmove(slash + 1, slash + 3, strlen(slash + 3) + 1);
  }

  curl_slist* headers = NULL;
  add_header(&headers, "X-Copy-From", src_encoded);
  add_header(&headers, "Content-Length", "0");
  //get source file entry
  dir_entry* de_src = check_path_info(src);
  if (de_src)
    debugf(DBG_LEVEL_EXT, "status cloudfs_copy_object(%s, %s): src file found",
           src, dst);
  else
    debugf(DBG_LEVEL_NORM,
           KRED"status cloudfs_copy_object(%s, %s): src file NOT found", src, dst);
  //pass src metadata so that PUT will set time attributes of the src file
  int response = send_request("PUT", dst_encoded, NULL, NULL, headers, de_src,
                              dst);
  curl_free(dst_encoded);
  curl_free(src_encoded);
  curl_slist_free_all(headers);
  debugf(DBG_LEVEL_EXT, "exit: cloudfs_copy_object(%s,%s) response=%d", src, dst,
         response);
  return (response >= 200 && response < 300);
}

