static int maxbit(int n)
{
    int mask = 1 << (NUMPRI - 1);
    int max = NUMPRI - 1;

    while (mask) {
        if (n & mask) {
            return max;
        }
        max--;
        mask >>= 1;
    }

    return 0;
}

