   gchar *str = NULL;   
   GstElement *myencoder = (GstElement *)data;

   if (g_io_channel_read_line (source, &str, NULL, NULL, NULL) == G_IO_STATUS_NORMAL) {	
	  if (str[0] == 'k' && 
