Float Syn_ParseFilterEX_X(PNode *e, PNode *x, int lang)
{
  /* todoSCORE: Low score if adjective never preposed.
   * Sem_Parse already constrains on an individual concept basis.
   */
  if (PNodeFeatureIn(e, F_PP) || PNodeFeatureIn(x, F_DETERMINER)) return(0.0);
  if (x->pn1->feature == F_ADJP) {
  /* Disallow e:[E ...] x:[X [E ] ...]: the E's should be one.
   * "I'm having dinner"
   */
    return(0.0);
  }
  if (x->pn1 && x->pn1->feature == F_PRONOUN &&
      x->pn2 == NULL) {
  /* Disallow [American who]. */
    return(0.0);
  }
  return(1.0);
}

int readFlt(float *flt_ptr) {
	// max 100 characters accepted
	char arr[100];
	int is_neg = 0, pow_10 = 0;
	float val = 0.00;
    int dot_encountered = 0;
    int count = 0;
    int byte_count = 20;

    __asm__ __volatile__ (
          "movl $0, %%eax \n\t"
          "movq $1, %%rdi \n\t"
          "syscall \n\t"
          :
          :"S"(arr), "d"(byte_count)
    ) ;

    if (arr[count] == '-'){
        is_neg = -1;
        count++;
    }
    else{
        is_neg = 1;
    }

    while(arr[count] != '\n' && arr[count] != ' ' && arr[count] != '\t'){
        // printf("%f\n", (float)val);
        // printf("%c\n", arr[count]);
        if ((((int)arr[count]-'0' > 9) || ((int)arr[count]-'0' < 0)) && (arr[count]!='.')) 
            return ERR;
        else if (arr[count]=='.' && dot_encountered){
            return ERR;
        }
        if (arr[count] == '.'){
            dot_encountered = 1;
            count++;
            continue;
        }
        if (dot_encountered){
            int  temp_div = 10;
            for (int k=0; k<pow_10; k++){
                temp_div *= 10;
            }
            // printf("\n\n%f\n\n" ,(float)(arr[count] - '0') / temp_div);
            val += ((float)(arr[count] - '0') / temp_div);
            pow_10++;
        }
        else{
            val *= 10.00;
            val = val + (float)(arr[count] - '0');
        }
        count++;
    }

    if (is_neg == -1){
        val = -1 * val;
    }
    *flt_ptr = val;
	return OK;
}

void ocp_nlp_opts_initialize_default(void *config_, void *dims_, void *opts_)
{
    ocp_nlp_dims *dims = dims_;
    ocp_nlp_config *config = config_;
    ocp_nlp_opts *opts = opts_;

    ocp_qp_xcond_solver_config *qp_solver = config->qp_solver;
    ocp_nlp_dynamics_config **dynamics = config->dynamics;
    ocp_nlp_cost_config **cost = config->cost;
    ocp_nlp_constraints_config **constraints = config->constraints;
    ocp_nlp_reg_config *regularize = config->regularize;

    int N = dims->N;

    opts->reuse_workspace = 1;
#if defined(ACADOS_WITH_OPENMP)
    #if defined(ACADOS_NUM_THREADS)
    opts->num_threads = ACADOS_NUM_THREADS;
    // printf("\nocp_nlp: openmp threads from macro = %d\n", opts->num_threads);
    #else
    opts->num_threads = omp_get_max_threads();
    // printf("\nocp_nlp: omp_get_max_threads %d", omp_get_max_threads());
    #endif
#endif
    // printf("\nocp_nlp: openmp threads = %d\n", opts->num_threads);

    opts->globalization = FIXED_STEP;
    opts->print_level = 0;
    opts->step_length = 1.0;
    opts->levenberg_marquardt = 0.0;


    /* submodules opts */
    // qp solver
    qp_solver->opts_initialize_default(qp_solver, dims->qp_solver, opts->qp_solver_opts);

    // regularization
    regularize->opts_initialize_default(regularize, dims->regularize, opts->regularize);

    // dynamics
    for (int i = 0; i < N; i++)
    {
        dynamics[i]->opts_initialize_default(dynamics[i], dims->dynamics[i], opts->dynamics[i]);
    }

    // cost
    for (int i = 0; i <= N; i++)
    {
        cost[i]->opts_initialize_default(cost[i], dims->cost[i], opts->cost[i]);
    }

    // constraints
    for (int i = 0; i <= N; i++)
    {
        constraints[i]->opts_initialize_default(constraints[i], dims->constraints[i], opts->constraints[i]);
    }

    // globalization
    opts->alpha_min = 0.05;
    opts->alpha_reduction = 0.7;
    opts->full_step_dual = 0;
    opts->line_search_use_sufficient_descent = 0;
    opts->globalization_use_SOC = 0;
    opts->eps_sufficient_descent = 1e-4; // Leineweber1999: MUSCOD-I eps_T = 1e-4 (p.89); Note: eps_T = 0.1 originally proposed by Powell 1978 (Leineweber 1999, p. 53)

