int main(int argc, char ** argv)
{
  static struct option long_opts[] =
  {
    {"threads",    optional_argument, NULL, 't'},
    {"iterations", optional_argument, NULL, 'i'},
    {"yield",      required_argument, NULL, 'y'},
    {"sync",       required_argument, NULL, 's'},
    {0,0,0,0}
  };

  int opt = 0;
  while((opt = getopt_long(argc, argv, "t:i:ys:", long_opts, NULL)) != -1)
  {
    switch(opt)
		{
			case 't':
        if (optarg)
				    num_threads = atoi(optarg);
				break;

			case 'i':
        if(optarg)
				    num_iterations = atoi(optarg);
				break;

      case 'y':
      if(optarg != NULL)
        set_yield_args(optarg);
      else
      {
        fprintf(stderr, "Usage: --yield=[idl]\n");
        exit(1);
      }
      break;

      case 's':
      if (*optarg == 'm')
        opt_sync_mutex = 1;
      else if (*optarg == 's')
        opt_sync_spin_lock = 1;
      else
      {
        fprintf(stderr, "Usage: --sync={m,s}\n");
        exit(1);
      }
      break;
      default:
          fprintf(stderr, "Usage: [ --threads=# --iterations=# --yield=[idl] --sync={m,s} ]\n");
          exit(1);
      }
    }


    //initalize head of linked list
    list = malloc(sizeof(SortedList_t));
    list->key = NULL;
    list->next = list;
    list->prev = list;

    //create and initalize the required number of list elements
    int num_list_elements = num_threads * num_iterations;

    elements = malloc(sizeof(SortedListElement_t) * num_list_elements);
    int i;
    for(i=0; i < num_list_elements; i++)
    {
      char *str = malloc(7 * sizeof(char));
      rand_str(str, sizeof(str) - 1);
      //printf("%s\n",str);
      elements[i].key = str;
      //printf("Element #%i %s\n", i, elements[i].key);
    }

    pthread_t* threads = malloc(sizeof(pthread_t) * num_threads);

    signal(SIGSEGV, handler);
    //START LIST OPERATIONS
    struct timespec start, end;
    if(clock_gettime(CLOCK_PROCESS_CPUTIME_ID, &start) == -1)
      { perror("clock_gettime() error"); exit(1); }


      int tid=0;
      while(tid < num_threads)
      {
        //int offset = tid * num_iterations;
        int status = pthread_create(threads + tid, NULL, thread_func, elements + tid * num_iterations);
        if (status)
         { perror("pthread_create() error"); exit(1); }

        tid++;
      }

      tid=0;
      while(tid < num_threads)
      {
          //fprintf(stderr, "join loop reached\n");
          int status = pthread_join(*(threads +tid), NULL);
          //fprintf(stderr, "hanging in join\n");
          if (status)
           { perror("pthread_join() error"); exit(1); }


        tid++;
      }

    if(clock_gettime(CLOCK_PROCESS_CPUTIME_ID, &end) == -1)
         { perror("clock_gettime() error"); exit(1); }

    //END LIST OPERATIONS
    long long time_elapsed = (end.tv_sec - start.tv_sec) * 1000000000L + (end.tv_nsec - start.tv_nsec);

    if(SortedList_length(list) != 0)
    {
      fprintf(stderr, "List length error");
      exit(2);
    }

    free(elements);
    free(list);
    free(threads);


      //DETERMINE NAME OF TEST
      char test_name[64] = "list";
      if(opt_yield)
      {
        strcat(test_name, "-");
        if(opt_yield & INSERT_YIELD)
          strcat(test_name, "i");
        if(opt_yield & DELETE_YIELD)
          strcat(test_name, "d");
        if(opt_yield & LOOKUP_YIELD)
          strcat(test_name, "l");
      }
      else
      {
        strcat(test_name, "-none");
      }
      if(opt_sync_spin_lock)
      {
          strcat(test_name, "-");
          strcat(test_name, "s");
      }
      else if(opt_sync_mutex)
      {
          strcat(test_name, "-");
          strcat(test_name, "m");
      }
      else
      {
        strcat(test_name, "-none");
      }
      //printf("something\n");
      long long num_operations = num_iterations * num_threads * 3;

      long long time_per_operation = time_elapsed / num_operations;
      long long num_lists= (long long) 1;

      printf("%s,%d,%d,%lld,%lld,%lld,%lld\n", test_name, num_threads, num_iterations, num_lists, num_operations, time_elapsed, time_per_operation);

      return 0;

}

float alignLine(int POIID){
    float vecDiff[3], POILoc[3];
    float SpherePos[] = {me[0],me[1],me[2]};
	float magnitude;
    game.getPOILoc(POILoc,POIID);
    mathVecSubtract(vecDiff, POILoc, SpherePos, 3); // vecDiff is the "correct" facing of the sphere
    magnitude = mathVecMagnitude(vecDiff,3);
	for (int i = 0 ; i < 3; i++) { // Converts vecDiff into unit vector
		vecDiff[i] = vecDiff[i] / magnitude ;
	}
    float SphereAttitude[] = {me[6], me[7], me[8]};
    return mathVecInner(vecDiff, SphereAttitude, 3) > cosf(0.4) ; // smaller angles have higher cosines
	// returns if the angle between the actual and the correct facings of the sphere is less than the
	// accepted value.
}

index_t decomp (index_t n, index_t n0, real a[], index_t ip[]) {
	real  t;
	index_t nm1, k, kp1, m;
	register real *ank;
	register real *anj;
	register index_t i;
	register index_t j;

	Profile P_(P_decomp);
#ifdef DEBUGMEDIUM
	if (n <= 0)  ErrorExit("decomp: n <= 0");
	if (n0 <= 0) ErrorExit("decomp: n0 <= 0");
	if (n0 < n)  ErrorExit("decomp: n0 < n");
#endif
	nm1 = n - 1;
	ip[nm1] = 1;

	if (n > 1) {
		for (k=0; k<nm1; ++k) {
			kp1 = k + 1;  /* defined for efficiency only */
			ank = a  +  k * n0;  /* k-th column */

			/* In the k-th column beginning at the (k+1)-th row the
			   biggest element in that column (=pivot) is searched.
			*/
			m = k;
			for (i=kp1; i<n; ++i)  if ( dabs(ank[i]) > dabs(ank[m]) )  m = i;

			ip[k] = m;  t = ank[m];

			/* exchange step:  */
			if (m != k) {
				ip[nm1] *= -1;
				ank[m] = ank[k];
				ank[k] = t;
			}

			/* Was there a column with zero elements only? */
			if (t == 0.0e0) {  ip[nm1] = 0;  return kp1;  }    /* rank is k+1 */

			t = (-1.0e0) / t;
			for (i=kp1; i<n; ++i)  ank[i] *= t;

			for (j=kp1; j<n; ++j) {
				anj = a  +  j * n0;
				t = anj[m];      /* swap a_{mj} and a_{kj} */
				anj[m] = anj[k];
				anj[k] = t;
				if (t != 0.0e0)
					for (i=kp1; i<n; ++i)  anj[i] += ank[i] * t;  /* a_{ij} += a_{ik} t */
			}
		}
	}

	if (a[nm1 + nm1*n0] == 0.0e0) {  ip[nm1] = 0;  return n;  }

	return 0;
}

int nb_immeubles_visibles(Gratte_ciel * p, int i, int j) 
{ 
	int cmpt=0;
	int max=0;

	if(est_case_bordure(p,i,j) == 0)
		return -1;
	else
		{

			//Condition pour la bordure de gauche !	

			if(j==0 && (i>=1 && i<=p->n))
			{	
				for(j=1; j <= p->n ; j++)
				{					
					if(p->grille[(((p->n)+2)*i)+j] > max)
					{
						max = p->grille[(((p->n)+2)*i)+j];
						cmpt++;
					}

				}

			}

			//Condition pour la bordure de droite !	

			if(j==p->n + 1 && (i>=1 && i<=p->n))
			{	
				for(j= p->n; j >= 1 ; j--)
				{					
					if(p->grille[(((p->n)+2)*i)+j] > max)
					{
						max = p->grille[(((p->n)+2)*i)+j];
						cmpt++;
					}

				}
			}

			//Condition pour la bordure du haut !

			if(i == 0 && (j>=1 && j<=p->n))
			{	
				for(i = 1 ; i <= p->n ; i++)
				{					
					if(p->grille[(((p->n)+2)*i)+j] > max)
					{
						max = p->grille[(((p->n)+2)*i)+j];
						cmpt++;
					}

				}
			}

			//Condition pour la bordure du bas !

			if(i == p->n + 1 && (j>=1 && j<=p->n))
			{	
				for(i = p->n ; i >=1 ; i--)
				{					
					if(p->grille[(((p->n)+2)*i)+j] > max)
					{
						max = p->grille[(((p->n)+2)*i)+j];
						cmpt++;
					}

				}
			}



		}
		return cmpt;
}

int asn1PrtToStrm_HeaderCompressionInfoList (OSCTXT *pctxt, 
   const char* name, const HeaderCompressionInfoList* pvalue)
{
   HeaderCompressionInfo* pdata0;
   OSRTDListNode* pnode;
