T_BOOL ImgLay_FillRect(T_pImgLay layer, T_RECT area, T_COLOR color)
{
	T_U8 *ybuf, *ubuf, *vbuf;

	AK_ASSERT_PTR(layer, "ImgLay_FillRect(): Input Parameter Is Error!\n", AK_FALSE);

	if (!layer->bDataValid)
	{
		return AK_FALSE;
	}

	switch(layer->format)
	{
	case RGB888:
	case RGB565:
		Fwl_FillSolidRectOnRGB(layer->pData, layer->area.width, layer->area.height,\
				&area, color, layer->format);
		break;

	case YUV420:
		ImgLay_CalcYUVAddr(layer->pData, layer->area.width, layer->area.height);

		Fwl_FillSolidRectOnYUV(ybuf, ubuf, vbuf, layer->area.width, layer->area.height,\
				&area, color);
		break;

	case YUV422:	
	default:
		return AK_FALSE;
	}

	return AK_TRUE;
}

void	imgui_filters_group(t_rtv *rtv)
{
	const t_byte		fil_min = 0;
	const t_byte		fil_max = MAX_FILTER - 1;
	const static char	*filters[MAX_FILTER] = {
		"None",
		"Grayscale",
		"Sepia",
		"Invert",
		"Cartoon effect",
	};

	if (!ig_group_top_default("Filters"))
		return ;
	igPushID_Str("Filters");
	if (igSliderScalar("filter", ImGuiDataType_U8, \
		&rtv->filter, &fil_min, &fil_max, filters[rtv->filter], 0) \
	)
		rtv->flags |= FLAG_REDRAW;
	igPopID();
}

