int32_t write_thermo_val(struct thermo_stat *thermo)
{
    uint32_t bytes_written = 0;
    int fd;
    int32_t ret;

    ret = qapi_Fs_Open(THERMO_STAT_FILE, QAPI_FS_O_RDWR | QAPI_FS_O_CREAT, &fd);
    if (ret != QAPI_OK)
    {
        LOG_ERROR("File creation is failed !!!!\n");
        return FAILURE;
    }

    qapi_Fs_Write(fd, &(thermo->desired), 1, &bytes_written);

    LOG_VERBOSE("bytes_written num = %d\n", bytes_written);
    if (!bytes_written)
    {
        LOG_ERROR("Failed to store desired temperature\n");
        goto error;
    }
    bytes_written = 0;

    qapi_Fs_Write(fd, &(thermo->threshhold), 1, &bytes_written);
    if (!bytes_written)
    {
        LOG_ERROR("Failed to store desired temperature\n");
        goto error;
    }

    qapi_Fs_Write(fd, &(thermo->op_mode), 1, &bytes_written);
    if (!bytes_written)
    {
        LOG_ERROR("Failed to store desired temperature\n");
        goto error;
    }


    qapi_Fs_Close(fd);
    return 0;

error:
    qapi_Fs_Close(fd);
    return FAILURE;

}

static int char2int(int8_t x)
{
	int value = -1;
	switch(x)
	{
		case 'A':
		case 'B':
		case 'C':
		case 'D':
		case 'E':
		case 'F':
			value = x - 'A' + 10;
			break;
		case 'a':
		case 'b':
		case 'c':
		case 'd':
		case 'e':
		case 'f':
			value = x - 'a' + 10;
			break;
			case '0':
			case '1':
		case '2':
		case '3':
		case '4':
		case '5':
		case '6':
		case '7':
		case '8':
		case '9':
			value = x - '0';
				break;
		default:
			break;
		}
		return value;
}

