bool str_cmp(const char *astr, const char *bstr)
{
    if (astr == NULL) {
        return true;
    }

    if (bstr == NULL) {
        return true;
    }

    for (; *astr > '0' || *bstr > '0'; astr++, bstr++) {
        if (LOWER(*astr) != LOWER(*bstr)) {
            return true;
        }
    }

    return false;
}

