	if ((ret = get_usr_config(&pUserCfg)) != 0) {
		PIC_PRINT(SYS_ERR, "get usr config failed\n");
		goto fail1;
	}

	snx_nvram_integer_get(NVRAM_SPACE, NVRAM_PICTURE_UPBD, &intbuf);
