int prepare_ppp_files(t_conf_v250 *p_conf_v250, t_conf_ppp *p_conf_ppp)
{
    // form the name of options.dev
    char *pos_fw_slash1, *pos_fw_slash2; // fw slash position in dev name, e.g. /dev/ttyAPP4
    char opt_file_name[FILE_NAME_LENGTH];
    FILE *opt_file;

    // sanity check
    if (!p_conf_v250 || !p_conf_ppp || !p_conf_v250->dev_name ||
            !p_conf_ppp->ip_addr_srv || !p_conf_ppp->ip_addr_cli) {
        me_syslog(LOG_ERR,"Failed to create PPP configuration files");
        return -1;
    }

    // work out the name of /etc/ppp/options.devName file
    pos_fw_slash1 = strchr(p_conf_v250->dev_name, '/');
    pos_fw_slash2 = strrchr(p_conf_v250->dev_name, '/');

    // should be offset by 4 characters which is the length of /dev/
    if (!pos_fw_slash1 || !pos_fw_slash2 || ((pos_fw_slash2 - pos_fw_slash1) != 4)) {
        me_syslog(LOG_ERR,"Device name in unknown format %s", p_conf_v250->dev_name);
        return -1;
    }

    // memorize tty device name as we will use it for the pid file name
    strncpy(p_conf_ppp->tty_name, pos_fw_slash2+1, DEV_NAME_LENGTH-1);
    sprintf(opt_file_name, "/etc/ppp/options.%s", p_conf_ppp->tty_name);

    if ((opt_file = fopen(opt_file_name, "w")) == 0) {
        me_syslog(LOG_ERR,"Failed to open %s file\n", opt_file_name);
        return -1;
    }

    fprintf(opt_file, "# Auto-generated\n");

    fprintf(opt_file, "-detach\n");
    fprintf(opt_file, "nodefaultroute\n");
    fprintf(opt_file, "netmask 255.255.255.255\n");
    fprintf(opt_file, "%s:%s\n", p_conf_ppp->ip_addr_srv, p_conf_ppp->ip_addr_cli);
    fprintf(opt_file, "proxyarp\n");
    fprintf(opt_file, p_conf_v250->opt_hw_fc ? "crtscts\n" : "#crtscts\n");
    fprintf(opt_file, "noauth\n");
    fprintf(opt_file, "ms-dns %s\n", p_conf_ppp->ip_addr_srv);
    fprintf(opt_file, p_conf_ppp->debug ? "debug\n" : "#debug\n");
    fprintf(opt_file, "local\n");
    fprintf(opt_file, "mtu %ld\n", p_conf_ppp->mtu);
    fprintf(opt_file, "mru %ld\n", p_conf_ppp->mru);

    // some old RTUs don't support the PPP protocol field value of 80fd -
    // (Compression Control protocol - CCP)
    if (p_conf_ppp->disable_ccp) {
        fprintf(opt_file, "noccp\n");
    }

    // should these 2 echo options be user-configurable (e.g. through Web UI)?
    fprintf(opt_file, "lcp-echo-failure 3\n");  // 3 failures means peer is dead
    fprintf(opt_file, "lcp-echo-interval 5\n"); // echos every 5 seconds

    fclose(opt_file);

    return 0;
}

NB_DEF NB_Error
NB_NavigationGetTrafficGuidanceInformation(NB_Navigation* navigation, NB_GuidanceMessage* message, double* playtimes,
                                           nb_boolean* isOverAll, nb_boolean* isCongestion, nb_boolean* isInCongestion,
                                           char* trafficColor)
{
    if (!navigation || !navigation->trafficState || !message)
    {
        return NE_INVAL;
    }

    if (NB_GuidanceMessageGetType(message) != NB_GMT_Traffic || NB_GuidanceMessageGetSource(message) != NB_NAS_Automatic)
    {
        return NE_INVAL;
    }

    if (isOverAll)
    {
        *isOverAll = FALSE;
    }
    if (isCongestion)
    {
        *isCongestion = FALSE;
    }
    if (isInCongestion)
    {
        *isInCongestion = FALSE;
    }
    if (trafficColor)
    {
        *trafficColor = '\0';
    }
    if (navigation->trafficState->currentManeuverPos == NB_NMP_TrafficCongestion)
    {
        if (isCongestion)
        {
            *isCongestion = TRUE;
        }
        if (isInCongestion)
        {
            *isInCongestion = navigation->trafficState->nextCongestionIn;
        }
        if (trafficColor)
        {
            switch (navigation->trafficState->nextCongestionSeverity) {
                case NB_NTC_Severe:
                    *trafficColor = 'R';
                    break;
                case NB_NTC_Moderate:
                    *trafficColor = 'Y';
                    break;
                default:
                    *trafficColor = 'G';
                    break;
            }
        }
    }
    else
    {
        if (isOverAll)
        {
            *isOverAll = TRUE;
        }
        if (trafficColor)
        {
            NB_NavigationGetTrafficColor(navigation, trafficColor);
        }
    }

    if (playtimes)
    {
        *playtimes = NB_GuidanceMessageGetPlaybackTime(message);
    }


    return NE_OK;
}

static struct _output_queues *add_tag_count(struct _output_queues *q, char *tc, struct _output_spec *output_spec, uint64_t *num_selects)
{
	struct _output_queues *ret = q;
	char read_group_name[RGNMMAXLEN];
	int len;
	int rgnmlen;
	char *p;
	uint64_t total_reads;
	struct _read_output_queue *roq;

	if(ret == NULL) {
		if((ret = malloc(sizeof(struct _output_queues))) == NULL) {
			fprintf(stderr, "Failed to malloc _output_queues struct\n");
			exit(-99);
		}

		ret->lane_nonpairs_queue = ret->lane_pairs_queue = ret->read_group_queues = NULL;
	}

	/* parse RG count spec */
	len = strlen(tc);
	if(len > 0) len--;
	for(p=tc+len; p>tc; p--) { /* format: <RG_val>:<count> */
		if(!isdigit(*p)) {
			if(*p == ':') {
				break;
			}
			if(*(p-1) != '0' || *p != 'x') {
				fprintf(stderr, "Invalid format %s for tag count spec\n", tc);
				return(ret);	/* if only invalid tag counts given, there will be no output */
			}
		}
	}
	if(*p != ':' || (rgnmlen = p-tc) <= 0) {
		fprintf(stderr, "Invalid format %s for tag count spec\n", tc);
		return(ret);	/* if only invalid tag counts given, there will be no output */
	}
	if(rgnmlen >= RGNMMAXLEN) {
		fprintf(stderr, "RG name too long in tag count spec: %s\n", tc);
		return(ret);	/* if only invalid tag counts given, there will be no output */
	}
	memcpy(read_group_name, tc, rgnmlen);
	read_group_name[rgnmlen] = '\0';
	total_reads = convert_numarg('t', p+1);

	if(ret->read_group_queues == NULL || get_rg_params(ret->read_group_queues, read_group_name) == NULL) {
		roq = new_roq(read_group_name, total_reads, num_selects, output_spec, 1);	/* can't currently specify single-end tagged here */
		if(tsearch(roq, &(ret->read_group_queues), compare_oq) == NULL) {
			fprintf(stderr, "Failed to add read group %s to read_group_queues\n", roq->read_group);
			exit(-99);
		}
	}
	else {
		fprintf(stderr, "Output queue for RG %s already exists in add_tag_count()\n", read_group_name);
	}

	return(ret);
}

