static char	*a_line(char **str)
{
	char	*buff;
	char	*line;
	char	*truc;

	buff = ft_strchr(*str, '\n');
	truc = NULL;
	if (buff)
	{
		if (!(line = ft_strndup(*str, buff - *str)))
			return (NULL);
		truc = *str;
		if (!(*str = ft_strdup(buff + 1)))
			return (NULL);
		free(truc);
	}
	else if (!(line = ft_strdup(*str)))
		return (NULL);
	if (!(*str) || !truc)
	{
		free(*str);
		*str = NULL;
	}
	return (line);
}

