RESULT SPI_Stop(HSPI SPI)
{
	// check SPI handle
	if(SPI!=0)
		return FAIL;

	// check state
	if(!(SPCR&(1<<SPE)))
		return FAIL;

	// if SPI is a system SPI and guard is watching for a threat
	// then return failure
	if(SPI_IS_SYSTEM_SPI&&Guard_IsWatching())
		return FAIL;

	// stop sransmission by pulling high the SS pin
	PORT_SPI |= (1<<DD_SS);

	// return success
	return SUCCESS;
}

