int Acowa_MoveReadPtr(RingBuffer *self, int element_count)
{
	if (NULL == self) {
		return 0;
	}

	const int free_elements = (int)Acowa_available_write(self);
	const int readable_elements = (int )Acowa_available_read(self);
	int read_pos = (int)self->read_pos;

	if (element_count > readable_elements) {
		element_count = readable_elements;
	}
	if (element_count < -free_elements) {
		element_count = -free_elements;
	}

	read_pos += element_count;
	if (read_pos > (int)self->element_count) {
		read_pos -= (int)self->element_count;
		self->rw_wrap = SAME_WRAP;
	}
	if (read_pos < 0) {
		read_pos += (int)self->element_count;
		self->rw_wrap = DIFF_WRAP;
	}

	self->read_pos = (size_t)read_pos;

	return element_count;
}

static int wstat_size(Spwstat *wstat, int dotu)
{
	int size = 0;

	if (wstat == NULL)
		return 0;

	size = 2 + 4 + 13 + 4 +	/* type[2] dev[4] qid[13] mode[4] */
	    4 + 4 + 8 +		/* atime[4] mtime[4] length[8] */
	    8;			/* name[s] uid[s] gid[s] muid[s] */

	if (wstat->name)
		size += strlen(wstat->name);
	if (wstat->uid)
		size += strlen(wstat->uid);
	if (wstat->gid)
		size += strlen(wstat->gid);
	if (wstat->muid)
		size += strlen(wstat->muid);

	if (dotu) {
		/* n_uid[4] n_gid[4] n_muid[4] extension[s] */
		size += 4 + 4 + 4 + 2;
		if (wstat->extension)
			size += strlen(wstat->extension);
	}

	return size;
}

