	return arr;
}

enum env_rc env_get_bool(char const * name, bool * result)
{
    assert(result != NULL);

    // Only store enough bytes to store the longest false/true value: `false`.
    size_t len;
    char buffer[6];
    enum env_rc rc = env_get(name, &len, buffer, ARRAY_SIZE(buffer));
    if (rc != ENV_RC_OK)
        return rc;

    // Convert the environment variable value to lower-case.
    for (size_t i = 0; i < len; ++i)
        buffer[i] = tolower(buffer[i]);

    bool success = parse_bool(buffer, result);
    if (!success)
        return ENV_RC_INVALID_VALUE;

    return ENV_RC_OK;
}

static int fuse_mfdoom_getattr(const char *path, struct stat *stbuf)
{
    mfdoom_dirent*   dirent;

    memset(stbuf, 0, sizeof(struct stat));

    dirent = find_dirent(path, 0);
    if (dirent == NULL)
        return -ENOENT;
    if (dirent->type == TYPE_DIR) {
        /*
         * We don't support permissions so we make everything the same.
         */
        stbuf->st_mode = S_IFDIR | 0755;
        /*
         * NEEDSWORK: nlink should be 2 plus number of subdirectories.
         */
        stbuf->st_nlink = 2;
    }
    else {
        /*
         * We don't support permissions so we make everything the same.
         */
        stbuf->st_mode = S_IFREG | 0644;
        stbuf->st_nlink = 1;
    }
    stbuf->st_size = dirent->size;
    stbuf->st_uid = uid;
    stbuf->st_gid = gid;
    stbuf->st_blksize = superblock.s.block_size;
    /*
     * Since we don't support timestamps, set everything to the mount time.
     */
    stbuf->st_atime = stbuf->st_ctime = stbuf->st_mtime = mount_time;
    return 0;
}

