	char	*res;
	short	len;
	short	i;
	short	sign;

	len = ft_intlen(n);
	if (!(res = ft_strnew(len)))
		return (NULL);
	i = 0;
	sign = 1;
	if (n == 0)
		res[i] = '0';
	if (n < 0)
	{
		res[i] = '-';
		sign = -1;
	}
	while (n != 0)
	{
		res[len - 1] = (sign * (n % 10)) + 48;
		n = n / 10;
		len = len - 1;
	}
	return (res);
}

