uint8_t get_obd_DntPtc(void)
{
	uint8_t data[2];
	uint16_t i,j;
	uint16_t res;
	uint32_t read_addr = OBD_DNTPTC_START_ADDR;

	osMutexWait(spi_flash_mutex_id, osWaitForever);

	W25QXX_set_DieID(DIE_NUM_0);
	W25QXX_Read(data,read_addr,sizeof(data));
	read_addr +=sizeof(data);
	while(read_addr < OBD_DNTPTC_END_ADDR)
	{
	  res=data[1];
		W25QXX_Read(data,read_addr,sizeof(data));
		if(data[0]==0xaa)
		{
			res=data[1];
			read_addr += sizeof(data);
			if(read_addr >=OBD_DNTPTC_END_ADDR)
			{	
        osMutexRelease(spi_flash_mutex_id);				
				return res;
			}
		  W25QXX_Read(data,read_addr,sizeof(data));
			if(data[0]==0xaa){
				read_addr += sizeof(data);
			  break;
			}
			else
			{
         osMutexRelease(spi_flash_mutex_id);				
			   return res;	
			}
		}else{
     osMutexRelease(spi_flash_mutex_id);			
		 return res;
		}	
	}
	 osMutexRelease(spi_flash_mutex_id);
	 return res;

}

static int lr388k7_resume(struct lr388k7 *ts)
{
	u8 u8_status = 0;
	int irq_value;

	lr388k7_start(ts);

	lr388k7_send_signal(g_st_state.u32_pid, LR388K7_SIGNAL_WAKE);


	if (g_st_dbg.wakeup.enable == 2)
		g_st_dbg.wakeup.enable = g_u16_wakeup_enable;

	if (IS_DBG) {
		g_st_dbg.u8ForceCap = 0;
		g_st_dbg.u8Dump = 0;
		g_st_dbg.slowscan.enable = 0;

		lr388k7_send_signal(g_st_state.u32_pid, LR388K7_SIGNAL_CTRL);
	}

	if (g_st_dbg.wakeup.enable == 0)
		return 0;

	/* check irq */
	irq_value = gpio_get_value(ts->gpio_irq);
	if (!irq_value) {

		u8_status = lr388k7_clear_irq();

		while (u8_status) {

			lr388k7_event_handler(u8_status);
			irq_value = gpio_get_value(ts->gpio_irq);

			if (!irq_value)
				u8_status = lr388k7_clear_irq();
			else
				u8_status = 0;
		}
	}

	return 0;
}

