int CalcMaximumSubSeq(int *Seq)
{
    int SeqLen = Seq[0];
    int SuffixMax = 0;
    int GlobalMax = 0;
    int Index;
    for(Index = 1; Index < SeqLen; ++Index)
    {
        if(SuffixMax + Seq[Index ] > GlobalMax)
        {
            SuffixMax += Seq[Index ];
            GlobalMax = SuffixMax;
        }
        else if( SuffixMax + Seq[Index ] > SuffixMax )
        {
            SuffixMax += Seq[Index ];
        }
        else
        {
            SuffixMax = SuffixMax+Seq[Index ] > 0 ? SuffixMax+Seq[Index ] : 0;
        }
    }
    return GlobalMax;
}

