static IRBlock* endBlock(IRBuilder* u) {
  auto b = u->b;
  assert(b != NULL); // has current block

  // Move block-local vars to long-term definition data.
  // First we fill any holes in defvars.
  while (u->defvars.len <= b->id) {
    ArrayPush(&u->defvars, NULL, u->mem);
  }
  if (u->vars->len > 0) {
    u->defvars.v[b->id] = u->vars;
    u->vars = SymMapNew(8, u->mem);  // new block-local vars
  }

  u->b = NULL;  // crash if we try to use b before a new block is started
  return b;
}

int send_spec_len_data(int fd, unsigned char* send_buf, unsigned short spec_send_data_len)
{
	int nwritten, retry_cnt = 0;
	int nleft = spec_send_data_len;

	while(nleft > 0)
	{
		if((nwritten = write(fd, send_buf, nleft)) < 0)
		{
			if(nleft == spec_send_data_len)
				return -1;  /* error occur, return -1*/
			else
				break;  /* error, return amount written so far */
		}
		else if(nwritten == 0)
		{
			if(retry_cnt++ > 3)
			{
				break;
			}
			else
			{
				usleep(50000);
			}
		}

		nleft -= nwritten;
		send_buf += nwritten;
	}

	return (spec_send_data_len- nleft);
}

int uv_fs_event_stop(uv_fs_event_t* handle) {
  int r;
  r = 0;

  if (!uv__is_active(handle))
    return 0;

  uv__handle_stop(handle);

#if defined(__APPLE__)
  if (!uv__has_forked_with_cfrunloop)
    r = uv__fsevents_close(handle);
#endif

  if (handle->event_watcher.fd != -1) {
    uv__io_close(handle->loop, &handle->event_watcher);
    uv__close(handle->event_watcher.fd);
    handle->event_watcher.fd = -1;
  }

  uv__free(handle->path);
  handle->path = NULL;

  return r;
}

