int main_operator(int p, int q) {
  int op = tokens[p].type;
  int op_position = p;
  bool init = false;
  for (int i = p; i <= q; ++i) {
    if (tokens[i].type == '(') {
      int tmp = 1;
      i++;
      while(true) {
        if (tokens[i].type == '(') { tmp++; }
        else if (tokens[i].type == ')') { tmp--; }
        if (tmp == 0) break;
        i++;
      }
      if (i >= q) break;
    }
    else if (tokens[i].type == DEREF ||
             tokens[i].type == TK_NUM ||
             tokens[i].type == TK_SIXT ||
             tokens[i].type == TK_REG) continue;
    else {
      if (init == false) {
        op = tokens[i].type;
        op_position = i;
        init = true;
        continue;
      }
      else if (priority(op, tokens[i].type) == false) {
        op = tokens[i].type;
        op_position = i;
      }
    }
  }
  return op_position;
}

