int sys_sigsend(pid_t pid, int signr)
{
	struct task **p;

	for (p = task_table; p < task_table + NR_TASK; p++) {
		if ((*p)->pid == pid) {
			(*p)->sigarrive |= 1 << (signr - 1);
			if ((*p)->state == TASK_STATE_READY) {
				(*p)->state = TASK_STATE_READY;
				sched();
			}
			return 0;
		}
	}
	return -ERSCH;
}

