int
orc_program_add_source_full (OrcProgram *program, int size, const char *name,
    const char *type_name, int alignment)
{
  int i = ORC_VAR_S1 + program->n_src_vars;

  if (program->n_src_vars >= ORC_MAX_SRC_VARS) {
    orc_program_set_error (program, "too many source variables allocated");
    return 0;
  }

  program->vars[i].vartype = ORC_VAR_TYPE_SRC;
  program->vars[i].size = size;
  if (alignment == 0) alignment = size;
  program->vars[i].alignment = alignment;
  program->vars[i].name = strdup(name);
  if (type_name) {
    program->vars[i].type_name = strdup(type_name);
  }
  program->n_src_vars++;

  return i;
}

static void insertNode(Node* _root, Node* _newNode, LessComparator _less, void* _item){

    if(_root->m_right == NULL && (!_less(_root->m_data, _item)))
	{
		_root->m_right = _newNode;
		_newNode->m_father=_root;
	}
	else if(_root->m_left == NULL && _less(_root->m_data, _item))
	{
		_root->m_left = _newNode;
		_newNode->m_father=_root;
	}
	else if (!_less(_root->m_data, _item))
	{
		insertNode(_root->m_right,_newNode, _less, _item);
	}	
	else
	{
		insertNode(_root->m_left, _newNode, _less, _item);
	}
	return;
}

char* findCommand(Command* commands, char* line) {
	if (commands == NULL) return NULL;
	Command* last;
	last = commands;
	int index = 0;
	while (last != NULL) {
		if (strcmp(line, last->shortForm) == 0 || strcmp(line, last->fullForm) == 0) {
			return last->fullForm;
		} else {
			index++;
			last = last->next;
		}
	}
	return (last != NULL) ? last->fullForm : NULL;
}

