int     howManyJesus(char *bible, char *jesus)
{
    unsigned int text_hash;
    int length = strlen(jesus);
    unsigned int patt_hash = goodHash(jesus, length);
    int count = 0;
    int j = 0;
    if(bible != NULL && jesus != NULL)
    {
        text_hash = goodHash(bible, length);
        while(bible[length-1] != '\0')
        {
            if (text_hash == patt_hash)
            {   
                j = 0;
                while(jesus[j] != '\0')
                {
                    if(jesus[j] != bible[j])
                        break;
                    j++;
                }
                if(jesus[j] == '\0')
                    count++;
            }
            text_hash -= bible[0]*(pow(7,0));
            text_hash /= 7;
            bible++;
            text_hash += bible[length-1]*(pow(7,length-1));
        }
    }
    return count;
}

void play_sample(int index, int volume, int channel)
{
	int length, outlen, ptr;
	int p, sample_ptr;
	char *current_sample;
	SDL_AudioCVT cvt;
	Mix_Chunk *chunk;

	if (nosound_flag)
	{
		/* day off! */
		return;
	}

	if (index == 0)
	{
		/* stop all sounds */
		stop_all_channels();
		return;
	}

	index = index - 1;
	LOG(("playing sample %d, volume %d, channel %d\n", index, volume, channel));

	if (cached_samples[index] != NULL)
	{
		LOG(("play cached sample\n"));
		Mix_PlayChannel(channel, cached_samples[index], 0);
		return;
	}

	sample_ptr = get_long(0xf90c);
	ptr = get_long(sample_ptr + index * 4);
	length = get_long(ptr);

	/* length plus some unknown flags */
	ptr = ptr + 8;

	LOG(("sample data starts at 0x%x\n", ptr));

	/* convert from 8000 mono 8bit, to 44100 stereo 16bit */
	SDL_BuildAudioCVT(&cvt, AUDIO_S8, 1, 8000, AUDIO_S16, 2, 44100);
	outlen = length * cvt.len_mult;

	cvt.len = length;
	cvt.buf = (char *)malloc(outlen);
	if (cvt.buf == NULL)
	{
		fprintf(stderr, "failed to allocate %d bytes for sample\n", outlen);
		return;
	}

	current_sample = (char *)cvt.buf;
	for (p=0; p<length; p++)
	{
		unsigned char u;
		signed char s;

		u = get_byte(ptr++);
		if (u > 0x80)
		{
			s = 0 - (u & 0x7f);
		}
		else if (u < 0x80)
		{
			s = u;
		}
		else
		{
			s = 0x00;
		}

		*current_sample++ = s;
	}

	SDL_ConvertAudio(&cvt);

	LOG(("sample length %d\n", length));

	chunk = (Mix_Chunk *)malloc(sizeof(Mix_Chunk));
	chunk->allocated = 1;
	chunk->abuf = cvt.buf;
	chunk->alen = outlen;
	chunk->volume = volume >> 1;

	cached_samples[index] = chunk;
	Mix_PlayChannel(channel, chunk, 0);
}

