static BOOL
TryExistingPage (
    PFSMAP   pfsmap,
    CommonMapView_t* pViewBase,
    PPROCESS pprc,
    DWORD    dwAddr,
    ULARGE_INTEGER liFileOffset,
    DWORD    fProtect
    )
{
    VMMTEResult result = VMMTE_SUCCESS;  // Anything but ALREADY_EXISTS
    BOOL fTakeLock = (PAGE_READWRITE & fProtect) 
                      && (pfsmap->dwFlags & MAP_ATOMIC);

    // Pre-increment the dirty counter.  The dirty counter can exceed the
    // true number of dirty pages in the view, but must never be too low.
    // If a R/W page is added to the view without incrementing dwDirty, and
    // another thread tries to flush, it'd underflow the dirty counter.
    if (PAGE_READWRITE & fProtect) {
    
        if(fTakeLock) {
            EnterCriticalSection(&PageOutCS);
        }
    
        InterlockedIncrement (&pViewBase->dwDirty);
        DEBUGCHK (pViewBase->dwDirty);
    }

    // Check if it's already in the mapfile page tree.  Otherwise, check if
    // it's already committed in the process.  Do it in this order so that
    // if another thread beats us to adding the page to the process (causing
    // MapVMCopy to fail) we can recover with a subsequent VMMapTryExisting call.
    
    if (!MapVMCopy (pfsmap, pprc, (LPVOID) dwAddr, liFileOffset,
                    VM_PAGE_SIZE, fProtect)) {
        
        result = VMMapTryExisting (pprc, (LPVOID) dwAddr, fProtect);
        
        if ((PAGE_READWRITE & fProtect) && (VMMTE_SUCCESS != result)) {  // ALREADY_EXISTS or FAIL
            DEBUGCHK (pViewBase->dwDirty);
            InterlockedDecrement (&pViewBase->dwDirty);
        }
    }
    
    if(fTakeLock) {
        LeaveCriticalSection(&PageOutCS);
    }
    
    DEBUGMSG (ZONE_MAPFILE && ZONE_PAGING, (L"TryExistingPage: successful\r\n"));
    return (VMMTE_FAIL!= result);
}

void update_roster(CHAR_DATA *ch, bool quit)
{
	ROSTER_DATA *roster;

	if (ch == NULL || IS_NPC(ch) || ch->pcdata == NULL)
		return;

	roster = ch->pcdata->roster;

	if (quit)
	{
		if (!roster && (roster = get_roster_by_name(ch->name, FALSE )) == NULL) // Check pcdata first, if unable to find, check by character name
		{
			printf_debug(
					"update_roster: unable to find roster data for quitting character %s",
					ch->name);
			return;
		}
		roster->last_login = current_time;
		roster->character = NULL;
		if (IS_IMMORTAL( ch ) && !IS_SET( roster->flags, ROST_IMMORTAL ))
			SET_BIT( roster->flags, ROST_IMMORTAL );
		else if (!IS_IMMORTAL( ch ) && IS_SET( roster->flags, ROST_IMMORTAL ))
			REMOVE_BIT( roster->flags, ROST_IMMORTAL );
		SET_ROSTER( ch, NULL );
	}
	else
	{
		if (!roster && (roster = get_roster_by_name(ch->name, FALSE )) == NULL) // New characters
		{
			roster = new_roster_data(TRUE);

			roster->character = ch;
			roster->clan = get_clan_by_id(CLAN_NONE);
			roster->pkilldata = new_pkill_data();
			free_string(roster->name);
			roster->name = str_dup(ch->name);
			roster->last_login = current_time;

			SET_ROSTER( ch, roster );
			save_all_rosters();
			return;
		}
		REMOVE_BIT( roster->flags, ROST_INACTIVE );
		REMOVE_BIT( roster->flags, ROST_AWAY );
		roster->last_login = current_time;
		roster->character = ch;
		if (IS_IMMORTAL( ch ) && !IS_SET( roster->flags, ROST_IMMORTAL ))
			SET_BIT( roster->flags, ROST_IMMORTAL );
		else if (!IS_IMMORTAL( ch ) && IS_SET( roster->flags, ROST_IMMORTAL ))
			REMOVE_BIT( roster->flags, ROST_IMMORTAL );
		SET_ROSTER( ch, roster );
		clanskill_check(ch);
	}
	save_roster_data(roster);
}

