        printf("Press 3 to Display\n");
        printf("Press 0 to Exit\n");
        scanf("%d",&n);
        switch (n) {
            case 1:insert(&q);
                    insort(&q);
                    disp(&q);
                break;
            case 2:delete(&q);
                    disp(&q);
                break;
            case 3:disp(&q);
                break;
        }
    }
    return 0;
}

