int16
low_resolution_log_div ( uint8 divisor , int16 max_power_dBm10 )
{
  int16 max_power_per_carrier_dBm10 = 0 ;
  switch ( divisor )
 {
   case 1: 
   max_power_per_carrier_dBm10 = max_power_dBm10 ;
   break;

  case 2:
    /* 1/2 linear is 3 dB lower in log */
    max_power_per_carrier_dBm10 = max_power_dBm10 - 30 ;
    break;

  case 3:
    /* 1/3 linear is 4.7 dB lower in log */
    max_power_per_carrier_dBm10 = max_power_dBm10 - 47 ;
    break;

  default:
    RF_MSG_1 ( RF_LOW , 
               "low_resolution_log_div() Don not know how to use %d" 
               , divisor ) ;

    break ;
  }
  return max_power_per_carrier_dBm10 ;
}

int		ft_atoi(const char *str)
{
	int		res;
	int		sign;

	res = 0;
	sign = 1;
	while (*str && (*str == '\r' || *str == '\n' || *str == '\t' ||
					*str == '\f' || *str == '\v' || *str == ' '))
		str++;
	if (str[0] == '-')
		sign = -1;
	if (*str == '+' || *str == '-')
		str++;
	while (*str && *str >= '0' && *str <= '9')
	{
		res = res * 10 + (*str - 48);
		if (res > 999999)
			return (-1);
		str++;
	}
	if (*str && !ft_isdigit(*str))
		exit_error_no_info("ERROR: Coordinate not Int!");
	return (res * sign);
}

char		**ft_strsplit(char const *s, char c)
{
	char	**foo;
	int		index;

	if (!s)
		return (NULL);
	index = 0;
	foo = (char **)malloc(sizeof(char *) * (ft_countstring(s, c) + 1));
	if (!foo)
		return (NULL);
	while (*s != '\0' && ft_countstring(s, c) > 0)
	{
		while (*s == c && *s != '\0')
			s++;
		while (*s != '\0' && *s != c)
		{
			if (!(foo[index] = ft_strsub(s, 0, getnextchar(s, c))))
				return (NULL);
			s = s + (getnextchar(s, c));
			index++;
		}
	}
	foo[index] = 0;
	return (foo);
}

