static int
diag_icmpv6_checksum_set(uint8 *packet)
{
    int i;
    uint16 checksum;
    uint8 pseudo_plus_icmpv6[BCMPTP_ND_CHECKSUM_PACKET_SIZE_OCTETS] = {0};

    /* Zero existing checksum. */
    sal_memset(packet + BCMPTP_ND_ICMPV6_CHECKSUM_OFFSET_OCTETS, 0,
               sizeof(uint16));

    /*
     * Make packet for checksum.
     * | IPv6 pseudo-header | ICMPv6 |.
     */

    /*
     * Insert IPv6 pseudo-header.
     * Ref. RFC 2460 - Internet Protocol, Version 6 (IPv6) Specification,
     *      Sect. 8.1, Upper-Layer Checksums.
     *  +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+
     *  |                                                               |
     *  +                                                               +
     *  |                                                               |
     *  +                         Source Address                        +
     *  |                                                               |
     *  +                                                               +
     *  |                                                               |
     *  +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+
     *  |                                                               |
     *  +                                                               +
     *  |                                                               |
     *  +                      Destination Address                      +
     *  |                                                               |
     *  +                                                               +
     *  |                                                               |
     *  +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+
     *  |                   Upper-Layer Packet Length                   |
     *  +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+
     *  |                      zero                     |  Next Header  |
     *  +-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+-+
     */
     sal_memcpy(pseudo_plus_icmpv6,
               packet + BCMPTP_ND_IPV6_SOURCE_IP_ADDRESS_OFFSET_OCTETS,
               BCMPTP_IPV6_ADDR_SIZE_BYTES);

    i = BCMPTP_IPV6_ADDR_SIZE_BYTES;
    sal_memcpy(pseudo_plus_icmpv6 + i,
               packet + BCMPTP_ND_IPV6_DESTINATION_IP_ADDRESS_OFFSET_OCTETS,
               BCMPTP_IPV6_ADDR_SIZE_BYTES);

    i += BCMPTP_IPV6_ADDR_SIZE_BYTES;
    _bcm_ptp_uint32_write(pseudo_plus_icmpv6 + i,
                         BCMPTP_ND_NEIGHBOR_ADVERTISEMENT_ICMPV6_SIZE_OCTETS);

    i += sizeof(uint32);
    _bcm_ptp_uint32_write(pseudo_plus_icmpv6 + i, BCMPTP_ND_NEXT_HEADER_ICMPV6);

    /* Insert ICMPv6. */
    i += sizeof(uint32);
    sal_memcpy(pseudo_plus_icmpv6 + i,
               packet + BCMPTP_ND_ICMPV6_OFFSET_OCTETS,
               BCMPTP_ND_NEIGHBOR_ADVERTISEMENT_ICMPV6_SIZE_OCTETS);

    /* Calculate checksum. */
    checksum = diag_ipv6_checksum(pseudo_plus_icmpv6,
                                  BCMPTP_ND_CHECKSUM_PACKET_SIZE_OCTETS);

    /* Set checksum. */
    _bcm_ptp_uint16_write(packet + BCMPTP_ND_ICMPV6_CHECKSUM_OFFSET_OCTETS, checksum);

    return BCM_E_NONE;
}

static int parse_error_packet(const void *buf, size_t len, mysql_parser_t *parser)
{
	const unsigned char *p = (const unsigned char *)buf + parser->offset;
	const unsigned char *buf_end = (const unsigned char *)buf + len;

	if (p + 9 > buf_end)
		return -2;

	parser->error = uint2korr(p + 1);
	p += 3;

	if (*p == '#')
	{
		p += 1;
		parser->net_state_offset = p - (const unsigned char *)buf;
		p += MYSQL_STATE_LENGTH;

		size_t msg_len = len - parser->offset - 9;
		parser->err_msg_offset = p - (const unsigned char *)buf;
		parser->err_msg_len = msg_len;
	} else {
		parser->err_msg_offset = (size_t)-1;
		parser->err_msg_len = 0;
	}

	parser->offset = len;
	parser->packet_type = MYSQL_PACKET_ERROR;
	parser->buf = buf;
	return 1;
}

Longword L_mpy_ll(Longword L_var1, Longword L_var2)
{
	double  aReg;
    Longword lvar;

    OP_COUNT(3);
    /* (unsigned)low1 * (unsigned)low1 */
    aReg = (double)(0xffff & L_var1) * (double)(0xffff & L_var2) * 2.0;

    OP_COUNT(1);
    /* >> 16 */
    aReg = (aReg / 65536);
    aReg = floor(aReg);

    OP_COUNT(1);
    /* (unsigned)low1 * (signed)high2 */
    aReg += (double)(0xffff & L_var1) * ((double)L_shr(L_var2,16)) * 2.0;

    OP_COUNT(1);
    /* (unsigned)low2 * (signed)high1 */
    aReg += (double)(0xffff & L_var2) * ((double)L_shr(L_var1,16)) * 2.0;

    OP_COUNT(1);
    /* >> 16 */
    aReg = (aReg / 65536);
    aReg = floor(aReg);

    OP_COUNT(1);
    /* (signed)high1 * (signed)high2 */
    aReg += (double)(L_shr(L_var1,16)) * (double)(L_shr(L_var2,16)) * 2.0;

    /* saturate result.. */
    lvar = L_saturate(aReg);

    return(lvar);
}

