int vmove(int a, int b, cub A[], cub B[])
{
    int x = Max(a, b), y = Min(a, b);
    if((x%10 < 1)&&(y%10 < 1)&&(x > 99))
        return 0;
    if(a/10 > b/10)
        for(int i = b; i < a; i += 10)
        {
            for(int j = 0; j < 9; j++)
            {
                if(A[j].place == i)
                    return 0;
                if(i != b)
                    if(B[j].place == i)
                        return 0;
            }
        }
    if(a/10 < b/10)
        for(int i = a+10; i <= b; i += 10)
        {
            for(int j = 0; j < 9; j++)
            {
                if(A[j].place == i)
                    return 0;
                if(i != b)
                    if(B[j].place == i)
                        return 0;
            }
        }
    return 1;
}

