	OW_writeByte(ow_port, ow_pin, OW_CMD_SKIPROM);
	_DelayUS(12);
	OW_writeByte(ow_port, ow_pin, OW_CONVERT_TEMPERATURE);
	_DelayMS(300);
	OW_reset(ow_port, ow_pin);
	_DelayUS(375);
	OW_writeByte(ow_port, ow_pin, OW_CMD_SKIPROM);
