int readGPIO(int gpio, int bank){
    unsigned char reg;
    unsigned char reg_data;

    if (bank==0){
        reg = GPIOA;
    } else if (bank==1){
        reg = GPIOB;
    }

    reg_data = readMCP23017(MCP23017_ADDRESS, reg);
    int value = (reg_data & (1<<gpio))>>gpio;
    return value;   
}

