int mmain(int argc, const char *argv)
{
   unsigned i;
   osd_options options;
   cli_options MRoptions;
   int result = 0;

   strcpy(gameName,argv);

   if(experimental_cmdline)
   {
      parse_cmdline(argv);
      if (log_cb)
         log_cb(RETRO_LOG_INFO, "Starting game from command line:%s\n",gameName);

      result = execute_game_cmd(ARGUV[ARGUC-1]);
   }
   else
   {
      if (log_cb)
         log_cb(RETRO_LOG_INFO, "Starting game:%s\n",gameName);
      result = execute_game(gameName);
   }

   if (result < 0)
      return result;

   if (log_cb)
      log_cb(RETRO_LOG_DEBUG, "Parameters:\n");

   for (i = 0; i < PARAMCOUNT; i++)
   {
      xargv_cmd[i] = (char*)(XARGV[i]);
      if (log_cb)
         log_cb(RETRO_LOG_DEBUG, " %s\n",XARGV[i]);
   }

   retro_osd_interface osd(options);
   osd.register_options();
   cli_frontend frontend(options, osd);

   result = frontend.execute(PARAMCOUNT, ( char **)xargv_cmd);

   xargv_cmd[PARAMCOUNT - 2] = NULL;

   return 1;
}

IL_FUNC IL_RETCODE GetTagOffsetByPath(IL_BYTE* data, IL_DWORD maxlen, const IL_TAG* pTagPath, IL_DWORD NumTags, IL_WORD *Offset, IL_DWORD* pdwLen, BYTE ifWithTag)
{
	IL_BYTE *pTag;

	_TagFind(data, maxlen, pTagPath, NumTags, pdwLen, &pTag, ifWithTag);
	if(pTag == NULL)
		return ILRET_DATA_TAG_NOT_FOUND;

	*Offset = (IL_WORD)(pTag - data);

	return 0;
}

