                                                   &UA_TYPES[UA_TYPES_INT32]);
    if(retval != UA_STATUSCODE_GOOD)
        return retval;

    /* Sort the array */
    sortArray(inputArray,input[0].arrayLength,output);
    return UA_STATUSCODE_GOOD;



}

