{

    int resultado;
    int retorno = -1;

    if(pResultado != NULL && (tipoOperador=='+' || tipoOperador=='-' || tipoOperador=='*'))
    {
        switch(tipoOperador)
        {
            case '+':
                resultado=num1+num2;
                retorno = 0;
            break;

            case '-':
                resultado=num1-num2;
                retorno = 0;
            break;

            case '*':
                resultado=num1*num2;
                retorno = 0;
            break;
        }
        *pResultado = resultado;
    }

    return retorno;

}

