double __fastcall sub_42A723(double a1)
{
  BOOL v1; // eax
  double v2; // xmm3_8
  double v3; // xmm2_8
  BOOL v4; // eax
  double result; // xmm0_8
  double v6; // [rsp+0h] [rbp-10h]
  double v7; // [rsp+0h] [rbp-10h]
  double v8; // [rsp+8h] [rbp-8h]
  double v9; // [rsp+8h] [rbp-8h]

  v1 = sub_41D67C(a1, 0.0);
  v2 = v8;
  v3 = v6;
  if ( !v1 )
    return fmin(v2, v3);
  v4 = sub_41D67C(v6, 0.0);
  v3 = v9;
  v2 = v7;
  if ( !v4 )
    return fmin(v2, v3);
  result = -0.0;
  if ( !(HIDWORD(v3) | HIDWORD(v2)) )
    return 0.0;
  return result;
}

