int asn1PrtToStrm_TransmissionRLC_Discard (OSCTXT *pctxt, 
   const char* name, const TransmissionRLC_Discard* pvalue)
{
   rtPrintToStreamOpenBrace (pctxt, name);

   switch (pvalue->t)
   {
      /* timerBasedExplicit */
      case 1:
      {
         asn1PrtToStrm_ExplicitDiscard (pctxt, "timerBasedExplicit", pvalue->u.timerBasedExplicit);
         break;
      }
      /* timerBasedNoExplicit */
      case 2:
      {
         asn1PrtToStrm_NoExplicitDiscard (pctxt, "timerBasedNoExplicit", &pvalue->u.timerBasedNoExplicit);
         break;
      }
      /* maxDAT-Retransmissions */
      case 3:
      {
         asn1PrtToStrm_MaxDAT_Retransmissions (pctxt, "maxDAT-Retransmissions", pvalue->u.maxDAT_Retransmissions);
         break;
