void	*ft_print_memory(void *addr, unsigned int size)
{
	unsigned int	i;
	int				length_line;

	i = 0;
	while (i < size)
	{
		if (size - i < 16)
			length_line = size - i;
		else
			length_line = 16;
		print_memory_address((addr + i));
		print_content_in_hex((addr + i), length_line);
		print_content((addr + i), length_line);
		write(1, "\n", 1);
		i = i + 16;
	}
	return (addr);
}

