static unsigned char
_LexerPrev(BarryLexer* L)
{
  int index = L->offset - 1;
  if (index < 0) {
    L->offset = 0;
    L->colno = 1;
    L->ch = L->src[0];
    L->pch = 0;
    return L->src[0];
  }
  else {
    --L->offset;
    if (L->lineno < 3) {
      L->colno = 1;
    }
    else {
      --L->colno;
    }

    L->ch = L->src[index];
    if (0 == index) {
      L->pch = 0;
    }
    else {
      L->pch = L->src[index - 1];
    }
    return L->src[index];
  }
}

