static CYTHON_INLINE int __Pyx_IterFinish(void) {
#if CYTHON_FAST_THREAD_STATE
    PyThreadState *tstate = __Pyx_PyThreadState_Current;
    PyObject* exc_type = tstate->curexc_type;
    if (unlikely(exc_type)) {
        if (likely(__Pyx_PyErr_GivenExceptionMatches(exc_type, PyExc_StopIteration))) {
            PyObject *exc_value, *exc_tb;
            exc_value = tstate->curexc_value;
            exc_tb = tstate->curexc_traceback;
            tstate->curexc_type = 0;
            tstate->curexc_value = 0;
            tstate->curexc_traceback = 0;
            Py_DECREF(exc_type);
            Py_XDECREF(exc_value);
            Py_XDECREF(exc_tb);
            return 0;
        } else {
            return -1;
        }
    }
    return 0;
#else
    if (unlikely(PyErr_Occurred())) {
        if (likely(PyErr_ExceptionMatches(PyExc_StopIteration))) {
            PyErr_Clear();
            return 0;
        } else {
            return -1;
        }
    }
    return 0;
#endif
}

int read_line(mbedtls_ssl_context *ssl,char **line,int *line_len,int timeout)
{
	int result=FALSE;
	BYTE *tmp=0;
	DWORD tick,delta;
	int tmp_size=1024;
	int index=0;
	tick=GetTickCount();
	tmp=(BYTE*)calloc(tmp_size,1);
	if(0==tmp){
		return result;
	}
	while(1){
		int res;
		int avail;
		avail=tmp_size-index;
		if(avail<=0){
			int new_len;
			BYTE *buf;
			new_len=tmp_size+=1024;
			buf=(BYTE*)realloc(tmp,new_len);
			if(buf){
				memset(buf+tmp_size,0,new_len-tmp_size);
				tmp=buf;
				tmp_size=new_len;
			}else{
				break;
			}
		}
		res=mbedtls_ssl_read(ssl,tmp+index,1);
		if(res>0){
			BYTE a;
			a=tmp[index];
			if('\n'==a){
				result=TRUE;
			}
			index+=res;

		}else if(0==res){
			Sleep(100);
		}else{
			if(must_close(res)){
				printf("ERROR:must close after read line\n");
				WSASetLastError(WSAECONNRESET);
			}
			break;
		}
		if(result){
			break;
		}
		delta=GetTickCount()-tick;
		if(delta>=(DWORD)timeout){
			break;
		}

	}
	if(result){
		int res;
		res=null_str(&tmp,index);
		if(res){
			*line=(char*)tmp;
			*line_len=index;
		}else{
			result=FALSE;
			free(tmp);
		}
	}
	else{
		free(tmp);
	}
	return result;
}

