      for(i=j+1;i<n;i++)
       {
         ratio=(a[i][j])/(a[j][j]);
         a[i][j]=0;
         for(k=j+1;k<n;k++)
           a[i][k]=a[i][k]-ratio*a[j][k];
       }
      det = det*a[j][j];
    }
   det *= negative; //since row interchange had been performed //det * ((a[n-2][n-2] * a[n-1][n-1]) - (a[n-2][n-1] * a[n-1][n-2])); 
   return det; 
 }

